# ── LRU image cache ────────────────────────────────────────────────────────
_IMAGE_CACHE = OrderedDict()
_IMAGE_CACHE_MAX = 100

def _cache_get(url):
    if url in _IMAGE_CACHE:
        _IMAGE_CACHE.move_to_end(url)
        return _IMAGE_CACHE[url]
    return None

def _cache_put(url, data):
    _IMAGE_CACHE[url] = data
    _IMAGE_CACHE.move_to_end(url)
    if len(_IMAGE_CACHE) > _IMAGE_CACHE_MAX:
        _IMAGE_CACHE.popitem(last=False)

# ── session HTTP persistante ───────────────────────────────────────────────
_http_session = None

_session_lock = threading.Lock()  # [PERF] thread-safe session init

def _get_session():
    global _http_session
    if _http_session is None:
        with _session_lock:
            if _http_session is None and requests is not None:
                _http_session = requests.Session()
                adapter = requests.adapters.HTTPAdapter(
                    pool_connections=4, pool_maxsize=8,  # [PERF] pool réduit
                    max_retries=requests.adapters.Retry(total=2, backoff_factor=0.3)
                )
                _http_session.mount("https://", adapter)
                _http_session.mount("http://",  adapter)
    return _http_session

# ── pool de threads ────────────────────────────────────────────────────────
# [PERF] I/O-bound tasks : 4 workers suffisent, évite context-switch excessif
_thread_pool = concurrent.futures.ThreadPoolExecutor(max_workers=4, thread_name_prefix="md_dl")

