# ── auto-update ───────────────────────────────────────────────────────────

def _version_tuple(v):
    """Convertit '2.4.0' en (2, 4, 0) pour comparaison."""
    try:
        return tuple(int(x) for x in v.strip().lstrip("v").split("."))
    except Exception:
        return (0,)

def check_for_update(root_window):
    """Vérifie silencieusement (thread) si une MàJ est disponible sur GitHub.
    Affiche une pop-up CTk sur le thread principal si c'est le cas."""
    def _check():
        try:
            import urllib.request as _ur, json as _json
            req = _ur.Request(_GITHUB_API_URL,
                              headers={"User-Agent": "FileScreen-Updater"})
            with _ur.urlopen(req, timeout=6) as r:
                data = _json.loads(r.read())

            latest_tag = data.get("tag_name", "").lstrip("v")
            if not latest_tag:
                return

            # Cherche un asset .exe (l'installeur)
            installer_url = None
            for asset in data.get("assets", []):
                if asset.get("name", "").lower().endswith(".exe"):
                    installer_url = asset["browser_download_url"]
                    break

            if (_version_tuple(latest_tag) > _version_tuple(APP_VERSION)
                    and installer_url):
                root_window.after(
                    0, lambda: _show_update_popup(root_window, latest_tag, installer_url)
                )
        except Exception as e:
            log(f"[UPDATE] Vérification échouée : {e}")

    threading.Thread(target=_check, daemon=True).start()


def _show_update_popup(root, new_version, download_url):
    """Pop-up customtkinter proposant la MàJ."""
    try:
        import customtkinter as _ctk_up
    except ImportError:
        return

    popup = _ctk_up.CTkToplevel(root)
    popup.title("Mise à jour disponible")
    popup.geometry("420x190")
    popup.resizable(False, False)
    popup.grab_set()
    popup.lift()
    popup.focus_force()

    _ctk_up.CTkLabel(
        popup,
        text=f"🎉  FileScreen {new_version} est disponible !",
        font=_ctk_up.CTkFont(size=15, weight="bold"),
    ).pack(pady=(26, 4))

    _ctk_up.CTkLabel(
        popup,
        text=f"Version installée : {APP_VERSION}",
        text_color="gray",
    ).pack()

    _ctk_up.CTkLabel(
        popup,
        text="L'installeur sera téléchargé puis lancé automatiquement.",
        text_color="gray",
        font=_ctk_up.CTkFont(size=11),
    ).pack(pady=(2, 0))

    def do_update():
        popup.destroy()
        _download_and_run_installer(root, download_url, new_version)

    btn_frame = _ctk_up.CTkFrame(popup, fg_color="transparent")
    btn_frame.pack(pady=18)
    _ctk_up.CTkButton(btn_frame, text="Mettre à jour",
                      command=do_update).pack(side="left", padx=10)
    _ctk_up.CTkButton(btn_frame, text="Plus tard",
                      fg_color="gray40",
                      hover_color="gray30",
                      command=popup.destroy).pack(side="left", padx=10)


def _download_and_run_installer(root, url, version):
    """Télécharge l'installeur avec une barre de progression, le lance, puis ferme l'app."""
    try:
        import customtkinter as _ctk_dl
    except ImportError:
        return

    prog_win = _ctk_dl.CTkToplevel(root)
    prog_win.title("Téléchargement…")
    prog_win.geometry("380x130")
    prog_win.resizable(False, False)
    prog_win.grab_set()
    prog_win.lift()

    lbl = _ctk_dl.CTkLabel(
        prog_win,
        text=f"Téléchargement de FileScreen {version}…",
        font=_ctk_dl.CTkFont(size=13),
    )
    lbl.pack(pady=(22, 8))

    bar = _ctk_dl.CTkProgressBar(prog_win, width=320)
    bar.set(0)
    bar.pack()

    def _set_label(txt):
        try:
            lbl.configure(text=txt)
        except Exception:
            pass

    def _dl():
        try:
            import urllib.request as _ur
            dest = os.path.join(
                tempfile.gettempdir(), f"FileScreen_Setup_{version}.exe"
            )
            req = _ur.Request(url, headers={"User-Agent": "FileScreen-Updater"})
            with _ur.urlopen(req) as resp:
                total = int(resp.headers.get("Content-Length") or 0)
                downloaded = 0
                with open(dest, "wb") as f:
                    while True:
                        chunk = resp.read(65536)
                        if not chunk:
                            break
                        f.write(chunk)
                        downloaded += len(chunk)
                        if total:
                            prog_win.after(0, bar.set, downloaded / total)

            prog_win.after(0, lambda: _launch(dest))
        except Exception as e:
            log(f"[UPDATE] Échec téléchargement : {e}")
            prog_win.after(0, lambda: _set_label("Erreur lors du téléchargement."))

    def _launch(installer_path):
        try:
            prog_win.destroy()
        except Exception:
            pass
        subprocess.Popen([installer_path], shell=True)
        root.after(600, root.destroy)   # ferme FileScreen proprement

    threading.Thread(target=_dl, daemon=True).start()

# ── historique des overlays ────────────────────────────────────────────────
_history_entries = []          # liste de dicts, max 200 entrées
_history_lock    = threading.Lock()
_history_callback = None       # appelé (thread-safe via after) quand nouvel item

def _push_history(entry):
    """Ajoute une entrée à l'historique (thread-safe). Appelé depuis Overlay.show()."""
    with _history_lock:
        _history_entries.insert(0, entry)   # plus récent en tête
        if len(_history_entries) > 200:
            _history_entries.pop()
    cb = _history_callback
    if cb is not None:
        try: cb(entry)
        except Exception: pass

# ── son d'annonce ──────────────────────────────────────────────────────────
_announce_sound_cache = {}

def _play_announce_sound(volume_pct):
    if not _PYGAME_OK: return
    try:
        key = round(volume_pct)
        if key in _announce_sound_cache:          # [PERF] hit rapide sans import
            _announce_sound_cache[key].play()
            return
        import numpy as np
        sr = 44100; dur = 0.18; freq = 880
        t    = np.linspace(0, dur, int(sr * dur), endpoint=False)
        wave = (np.sin(2 * np.pi * freq * t) * 32767).astype(np.int16)
        wave = (wave * np.linspace(1.0, 0.0, len(wave))).astype(np.int16)
        stereo = np.column_stack([wave, wave])
        snd = pygame.sndarray.make_sound(stereo)
        snd.set_volume(max(0.0, min(1.0, volume_pct / 100)))
        _announce_sound_cache[key] = snd
        _announce_sound_cache[key].play()
    except Exception as e:
        log(f"[SON] bip error: {e}")

# ══════════════════════════════════════════════════════════════════════════════
#  PARSING DES COMMANDES
#  Syntaxe supportée dans le message Discord :
#    @pseudo          → ciblage (tout le monde si absent)
#    ![anim]          → animation d'entrée : chute, spin, glitch, tremble,
#                                             zoom, yeet, fondu
#    #modif           → modificateur visuel : grand, petit, retourne, miroir,
#                                              nb
#    !fort  !muet     → volume override
#    !long  !flash    → durée override
# ══════════════════════════════════════════════════════════════════════════════

ANIMATIONS = {"chute", "spin", "glitch", "tremble", "zoom", "yeet", "fondu", "flou"}
MODIFIERS  = {"grand", "petit", "retourne", "miroir", "nb"}

def parse_commands(raw_text, mention_map=None):
    """
    Retourne (targets, animation, modifiers, volume_override, duration_override, clean_text)
    - targets          : liste de pseudos en minuscules ([] = tout le monde)
    - animation        : str ou None
    - modifiers        : set de str
    - volume_override  : float ou None (0.0-1.0)
    - duration_override: int ou None (secondes)
    - clean_text       : texte sans les tokens de commande
    mention_map        : dict {user_id_str: display_name} pour résoudre <@ID>
    """
    targets           = []
    animation         = None
    modifiers         = set()
    volume_override   = None
    duration_override = None

    # Résoudre les mentions Discord <@123456> ou <@!123456> en pseudo
    text = raw_text
    if mention_map:
        def _resolve(m):
            uid = m.group(1).lstrip("!")
            name = mention_map.get(uid, "")
            return f"@{name}" if name else ""
        text = re.sub(r'<@!?(\d+)>', _resolve, text)

    # tokens @pseudo — uniquement si @ est en début de mot (pas dans une adresse email)
    for m in re.finditer(r'(?<!\S)@(\S+)', text):
        val = m.group(1).lower().strip(".,!?")
        # Ignorer si ça ressemble à un domaine email (contient un point sans sous-@)
        if val and '.' not in val:
            targets.append(val)

    # token !anim  (ex: !chute  !spin  !glitch ...)
    # On cherche !mot où mot est une animation connue
    # Doit être précédé d'un espace ou début de chaîne pour éviter !fort etc.
    for _am in re.finditer(r'(?<![^\s])!(\w+)', text):
        if _am.group(1).lower() in ANIMATIONS:
            animation = _am.group(1).lower()
            break

    # tokens #modif
    for m in re.finditer(r'#(\w+)', text):
        if m.group(1).lower() in MODIFIERS:
            modifiers.add(m.group(1).lower())

    # !fort / !muet / !long / !flash  (indépendants du command_prefix)
    if re.search(r'!fort\b',  text): volume_override   = 1.0
    if re.search(r'!muet\b',  text): volume_override   = 0.0
    if re.search(r'!long\b',  text): duration_override = 30
    if re.search(r'!flash\b', text): duration_override = 1

    # nettoyage du texte affiché
    clean = text
    clean = re.sub(r'<@!?\d+>', '', clean)        # mentions user brutes
    clean = re.sub(r'<#\d+>', '', clean)              # mentions salon brutes
    clean = re.sub(r'(?<!\S)@\S+', '', clean)  # retire @pseudo mais pas les emails
    clean = re.sub(r'\$\[\w+\]', '', clean)   # compat ancienne syntaxe
    # retire !anim connus du texte affiché
    anim_pattern = '|'.join(ANIMATIONS)
    clean = re.sub(rf'(?<![^\s])!({anim_pattern})\b', '', clean)
    # retire uniquement les #modificateurs connus (pas les hashtags libres)
    modif_pattern = '|'.join(MODIFIERS)
    clean = re.sub(rf'#({modif_pattern})\b', '', clean)
    clean = re.sub(r'!(fort|muet|long|flash)\b', '', clean)
    clean = re.sub(r'\s{2,}', ' ', clean).strip()

    return targets, animation, modifiers, volume_override, duration_override, clean


# ── overlay queue ──────────────────────────────────────────────────────────
_overlay_queue = _queue.Queue()
_overlay_busy  = threading.Event()   # set = un overlay est en cours d'affichage
_overlay_busy.clear()                # au départ, libre
_app_root      = None                # référence globale à la fenêtre principale

def _destroy_active_overlays():
    """Détruit toutes les fenêtres Toplevel actives (overlay en cours)."""
    if _app_root is None: return
    for w in list(_app_root.winfo_children()):
        try:
            if isinstance(w, tk.Toplevel):
                w.destroy()
        except Exception: pass

def clear_overlay():
    """!clear — vide toute la queue ET l'overlay en cours."""
    while not _overlay_queue.empty():
        try: _overlay_queue.get_nowait()
        except _queue.Empty: break
    if _app_root:
        def _do():
            _destroy_active_overlays()
            _overlay_busy.clear()
        _app_root.after(0, _do)

def skip_to_next_overlay():
    """!skip — ferme uniquement l'overlay en cours, passe au suivant."""
    if _app_root:
        def _do():
            _destroy_active_overlays()
            _overlay_busy.clear()
        _app_root.after(0, _do)

def _process_overlay_queue(app_root):
    """Consomme la queue un élément à la fois.
    Un nouvel overlay ne démarre que lorsque le précédent a appelé son on_done
    (barre de progression terminée, ou yeet terminé)."""
    if not _overlay_busy.is_set():
        try:
            item = _overlay_queue.get_nowait()
            _overlay_busy.set()
            _thread_pool.submit(
                _prepare_and_show, app_root, item["content"], item["config"],
                _done_cb=lambda: app_root.after(0, _overlay_busy.clear))
        except _queue.Empty:
            pass
    app_root.after(20, _process_overlay_queue, app_root)  # [PERF] 20ms = réactif sans burn CPU

# ── helpers géométrie ──────────────────────────────────────────────────────
def _compute_position(config, sw, sh, W, H):
    mg = 30
    pos = config.get("position", "haut")
    if config.get("random_position", False):
        return (random.randint(mg, max(mg, sw-W-mg)),
                random.randint(mg, max(mg, sh-H-mg)))
    px = {
        "haut gauche": (mg, mg), "haut": ((sw-W)//2, mg),
        "haut droite": (sw-W-mg, mg), "bas gauche": (mg, sh-H-mg),
        "centre": ((sw-W)//2, (sh-H)//2), "bas droite": (sw-W-mg, sh-H-mg),
    }
    return px.get(pos, ((sw-W)//2, mg))

def _is_emoji_char(char):
    """Retourne True si le caractère est un emoji ou un caractère lié aux emojis."""
    cp = ord(char)
    return (
        0x1F000 <= cp <= 0x1FFFF or   # Emoji principaux (😀🎉🔥…)
        0x2600  <= cp <= 0x27BF or    # Divers symboles (☀✈➿…)
        0x2300  <= cp <= 0x23FF or    # Symboles techniques (⌚⏿…)
        0x2B00  <= cp <= 0x2BFF or    # Flèches et autres
        0xFE00  <= cp <= 0xFE0F or    # Sélecteurs de variation VS1-VS16
        cp == 0x200D or               # Zero Width Joiner (séquences ZWJ)
        0x1F1E0 <= cp <= 0x1F1FF or   # Indicateurs régionaux (drapeaux 🇫🇷)
        0x1F900 <= cp <= 0x1F9FF or   # Emoji supplémentaires
        0x1FA00 <= cp <= 0x1FAFF      # Symboles et pictogrammes étendus
    )


def _split_text_emoji(text):
    """
    Découpe `text` en alternance de segments texte normal / emojis.
    Retourne une liste de tuples (segment: str, is_emoji: bool).
    Les modificateurs ZWJ/VS sont absorbés dans le segment emoji précédent.
    """
    if not text:
        return []
    segments = []
    cur = ""
    cur_is_emoji = None
    for ch in text:
        cp = ord(ch)
        # Absorber ZWJ et sélecteurs de variation dans le segment emoji en cours
        if cur_is_emoji and (cp == 0x200D or 0xFE00 <= cp <= 0xFE0F):
            cur += ch
            continue
        # Combining Enclosing Keycap (⃣) : rattacher au caractère précédent → emoji
        if cp == 0x20E3:
            if cur_is_emoji is False and cur:
                cur += ch
                segments.append((cur, True))
                cur = ""
                cur_is_emoji = None
            else:
                cur += ch
            continue
        flag = _is_emoji_char(ch)
        if cur_is_emoji is None:
            cur = ch
            cur_is_emoji = flag
        elif flag == cur_is_emoji:
            cur += ch
        else:
            if cur:
                segments.append((cur, cur_is_emoji))
            cur = ch
            cur_is_emoji = flag
    if cur:
        segments.append((cur, cur_is_emoji))
    return segments


def _measure_mixed_line(line, font_text, font_emoji, font_size, draw):
    """Mesure la largeur totale d'une ligne mixte texte+emojis."""
    segments = _split_text_emoji(line)
    total = 0
    for seg, is_emoji in segments:
        fnt = font_emoji if is_emoji else font_text
        try:
            total += draw.textbbox((0, 0), seg, font=fnt)[2]
        except Exception:
            total += len(seg) * int(font_size * (0.9 if is_emoji else 0.6))
    return total


def _wrap_text(text, max_w, font, draw, font_size):
    """
    Découpe le texte en lignes en tenant compte des emojis.
    Utilise la font emoji pour la mesure des segments emoji.
    """
    if not text:
        return []
    # Police emoji au même corps que la police texte
    try:
        font_emoji = _load_emoji_font(font_size)
    except Exception:
        font_emoji = font

    words = text.split()
    lines = []
    cur = ""
    for w in words:
        test = (cur + " " + w).strip()
        tw = _measure_mixed_line(test, font, font_emoji, font_size, draw)
        if tw <= max_w - 20:
            cur = test
        else:
            if cur:
                lines.append(cur)
            cur = w
    if cur:
        lines.append(cur)
    return lines


def _draw_caption(draw, lines, font, font_size, img_w, img_h, bar_h):
    """
    Dessine les lignes de texte (avec emojis) en bas de l'image.
    Les emojis sont rendus avec la font emoji couleur (Segoe UI Emoji).
    Chaque segment est dessiné séquentiellement sur la même ligne.
    """
    LH = font_size + 6
    total_h = len(lines) * LH
    ty = max(4, img_h - total_h - 10 - bar_h)
    stroke = max(1, font_size // 10)

    try:
        font_emoji = _load_emoji_font(font_size)
    except Exception:
        font_emoji = font

    for line in lines:
        if not line:
            continue
        # Mesure totale de la ligne pour centrage
        line_w = _measure_mixed_line(line, font, font_emoji, font_size, draw)
        tx = max(0, (img_w - line_w) // 2)
        segments = _split_text_emoji(line)
        # Passe 1 : contour noir (stroke) sur les segments texte uniquement
        # (les emojis couleur n'ont pas besoin de contour)
        x_cur = tx
        for seg, is_emoji in segments:
            fnt = font_emoji if is_emoji else font
            try:
                seg_w = draw.textbbox((0, 0), seg, font=fnt)[2]
            except Exception:
                seg_w = len(seg) * int(font_size * (0.9 if is_emoji else 0.6))
            if not is_emoji:
                for ox in range(-stroke, stroke + 1):
                    for oy in range(-stroke, stroke + 1):
                        if ox == oy == 0:
                            continue
                        draw.text((x_cur + ox, ty + oy), seg, font=fnt, fill=(0, 0, 0))
            x_cur += seg_w
        # Passe 2 : texte en blanc + emojis en couleur
        x_cur = tx
        for seg, is_emoji in segments:
            fnt = font_emoji if is_emoji else font
            try:
                seg_w = draw.textbbox((0, 0), seg, font=fnt)[2]
            except Exception:
                seg_w = len(seg) * int(font_size * (0.9 if is_emoji else 0.6))
            draw.text((x_cur, ty), seg, font=fnt, fill=(255, 255, 255))
            x_cur += seg_w
        ty += LH

def _find_font_path(candidates):
    """Helper : cherche le premier fichier de police trouvé parmi une liste de noms."""
    win_dirs = [
        os.path.join(os.environ.get("WINDIR", "C:\\Windows"), "Fonts"),
        os.path.join(os.environ.get("LOCALAPPDATA", ""), "Microsoft", "Windows", "Fonts"),
    ]
    for fname in candidates:
        try: return ImageFont.truetype(fname, 1)  # dummy size — juste pour tester la présence
        except: pass
        for d in win_dirs:
            fp = os.path.join(d, fname)
            if os.path.exists(fp):
                return fp  # chemin absolu validé
    return None

@lru_cache(maxsize=8)
def _load_font(size):
    # Cherche Impact (style mème) puis fallbacks
    candidates = ["impact.ttf", "Impact.ttf", "arialbd.ttf", "Arial Bold.ttf",
                  "DejaVuSans-Bold.ttf", "LiberationSans-Bold.ttf"]
    win_dirs = [
        os.path.join(os.environ.get("WINDIR", "C:\\Windows"), "Fonts"),
        os.path.join(os.environ.get("LOCALAPPDATA", ""), "Microsoft", "Windows", "Fonts"),
    ]
    for fname in candidates:
        try: return ImageFont.truetype(fname, size)
        except: pass
        for d in win_dirs:
            fp = os.path.join(d, fname)
            try: return ImageFont.truetype(fp, size)
            except: pass
    return ImageFont.load_default()

@lru_cache(maxsize=8)
def _load_emoji_font(size):
    """Font avec support emoji couleur (Segoe UI Emoji sur Windows)."""
    candidates = ["seguiemj.ttf", "seguisym.ttf", "NotoColorEmoji.ttf",
                  "NotoEmoji-Regular.ttf", "TwitterColorEmoji.ttf", "arialbd.ttf"]
    win_dirs = [
        os.path.join(os.environ.get("WINDIR", "C:\\Windows"), "Fonts"),
        os.path.join(os.environ.get("LOCALAPPDATA", ""), "Microsoft", "Windows", "Fonts"),
    ]
    for fname in candidates:
        try: return ImageFont.truetype(fname, size)
        except: pass
        for d in win_dirs:
            fp = os.path.join(d, fname)
            try: return ImageFont.truetype(fp, size)
            except: pass
    return _load_font(size)

# ── barre de progression ───────────────────────────────────────────────────
def _animate_bar(win, cv, bar_id, bar_y0, CW, BAR_H, duration_s, sent_timestamp=None, on_done=None):
    """Barre de progression qui se vide sur duration_s secondes puis détruit la fenêtre.
    sent_timestamp est ignoré ici : la durée démarre toujours à partir de l'appel.
    on_done est appelé après destruction de la fenêtre (pour libérer la queue)."""
    interval = 50
    # On ignore sent_timestamp pour les animations : la durée part du moment
    # où l'animation est terminée (i.e. quand _start_bar est appelé).
    remaining_s = float(max(1.0, duration_s))
    deadline = time.time() + remaining_s

    cv.coords(bar_id, 0, bar_y0, CW, bar_y0 + BAR_H)

    def tick():
        if not win.winfo_exists():
            if on_done:
                try: on_done()
                except Exception: pass
            return
        remaining = deadline - time.time()
        frac = max(0.0, remaining / remaining_s)
        cv.coords(bar_id, 0, bar_y0, int(CW * frac), bar_y0 + BAR_H)
        if remaining > 0:
            win.after(interval, tick)
        else:
            cv.coords(bar_id, 0, bar_y0, 0, bar_y0 + BAR_H)
            def _destroy_and_signal():
                if win.winfo_exists():
                    win.destroy()
                if on_done:
                    try: on_done()
                    except Exception: pass
            win.after(100, _destroy_and_signal)

    win.after(interval, tick)


# ══════════════════════════════════════════════════════════════════════════════
#  MODIFICATEURS D'IMAGE
# ══════════════════════════════════════════════════════════════════════════════

def _apply_modifiers(img, modifiers, sw, sh):
    """Applique les modificateurs visuels à un objet PIL Image. Retourne la nouvelle image."""
    if "grand" in modifiers:
        max_w = int(sw * 0.80); max_h = int(sh * 0.80)
        img.thumbnail((max_w, max_h), Image.LANCZOS)
    elif "petit" in modifiers:
        img.thumbnail((180, 180), Image.LANCZOS)
    if "retourne" in modifiers:
        img = img.transpose(Image.FLIP_TOP_BOTTOM)
    if "miroir" in modifiers:
        img = img.transpose(Image.FLIP_LEFT_RIGHT)
    if "nb" in modifiers:
        img = img.convert("L").convert("RGB")
    return img


def _round_corners(img, radius=18):
    """Applique un masque RGBA avec coins arrondis sur une image PIL (RGBA ou RGB)."""
    img = img.convert("RGBA")
    w, h = img.size
    mask = Image.new("L", (w, h), 0)
    d = ImageDraw.Draw(mask)
    d.rounded_rectangle([0, 0, w - 1, h - 1], radius=radius, fill=255)
    result = Image.new("RGBA", (w, h), (0, 0, 0, 0))
    result.paste(img, mask=mask)
    return result


def _fetch_avatar_circle(url, size=36):
    """Télécharge l'avatar Discord et retourne une image RGBA circulaire."""
    try:
        sess = _get_session()
        raw = sess.get(url, timeout=5).content
        av = Image.open(io.BytesIO(raw)).convert("RGBA").resize((size, size), Image.LANCZOS)
        mask = Image.new("L", (size, size), 0)
        ImageDraw.Draw(mask).ellipse([0, 0, size - 1, size - 1], fill=255)
        result = Image.new("RGBA", (size, size), (0, 0, 0, 0))
        result.paste(av, mask=mask)
        return result
    except Exception:
        return None


def _build_author_badge(author, avatar_url, width, fs=13):
    """Crée une petite bannière RGBA discrète : avatar rond + pseudo.
    Retourne une image RGBA à coller en bas à gauche de l'overlay."""
    AV_SIZE = 28; PAD = 6; H = AV_SIZE + PAD * 2
    try:
        font_badge = _load_font(fs)
    except Exception:
        font_badge = None

    # Mesure la largeur du texte
    dummy = Image.new("RGB", (1, 1))
    dd = ImageDraw.Draw(dummy)
    try:
        tw = dd.textbbox((0, 0), author, font=font_badge)[2]
    except Exception:
        tw = len(author) * 8
    badge_w = min(width, PAD + AV_SIZE + PAD + tw + PAD)

    badge = Image.new("RGBA", (badge_w, H), (0, 0, 0, 0))
    # Fond semi-transparent arrondi
    bg = Image.new("RGBA", (badge_w, H), (0, 0, 0, 0))
    ImageDraw.Draw(bg).rounded_rectangle([0, 0, badge_w - 1, H - 1], radius=10, fill=(10, 10, 20, 175))
    badge.alpha_composite(bg)

    # Avatar
    av_img = _fetch_avatar_circle(avatar_url, AV_SIZE) if avatar_url else None
    if av_img:
        badge.alpha_composite(av_img, (PAD, PAD))

    # Texte pseudo
    bd = ImageDraw.Draw(badge)
    tx = PAD + AV_SIZE + PAD
    ty = (H - fs) // 2
    # Ombre légère
    bd.text((tx + 1, ty + 1), author, font=font_badge, fill=(0, 0, 0, 160))
    bd.text((tx, ty), author, font=font_badge, fill=(230, 230, 230, 220))
    return badge


def _apply_blur_effect(cv_widget, img_id, base_img, steps=8, interval=60):
    """Commence très flou et s'éclaircit progressivement vers l'image nette."""
    try:
        from PIL import ImageFilter
    except ImportError:
        return
    max_radius = steps * 1.5
    radius = [max_radius]
    def _step():
        if not cv_widget.winfo_exists(): return
        r = max(0.0, radius[0])
        if r > 0:
            blurred = base_img.filter(ImageFilter.GaussianBlur(radius=r))
        else:
            blurred = base_img
        photo = ImageTk.PhotoImage(blurred)
        cv_widget.itemconfig(img_id, image=photo)
        cv_widget._blur_photo = photo
        radius[0] -= 1.5
        if radius[0] > 0:
            cv_widget.after(interval, _step)
        else:
            # Image finale nette
            photo = ImageTk.PhotoImage(base_img)
            cv_widget.itemconfig(img_id, image=photo)
            cv_widget._blur_photo = photo
    # Afficher immédiatement la version floutée avant le premier tick
    try:
        first = base_img.filter(ImageFilter.GaussianBlur(radius=max_radius))
        photo = ImageTk.PhotoImage(first)
        cv_widget.itemconfig(img_id, image=photo)
        cv_widget._blur_photo = photo
    except Exception:
        pass
    cv_widget.after(interval, _step)


# ══════════════════════════════════════════════════════════════════════════════
#  ANIMATIONS D'ENTRÉE
#  Chaque fonction reçoit (win, cv, img_id, x_final, y_final, cw, ch)
#  et anime la fenêtre/canvas jusqu'à la position finale.
# ══════════════════════════════════════════════════════════════════════════════

def _anim_fondu(win, cv, img_id, x_final, y_final, cw, ch, on_done=None):
    """Apparition en fondu via transparence fenêtre."""
    alpha = [0.0]
    win.attributes("-alpha", 0.0)
    win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
    def _step():
        if not win.winfo_exists(): return
        alpha[0] = min(1.0, alpha[0] + 0.07)
        win.attributes("-alpha", alpha[0])
        if alpha[0] < 1.0:
            win.after(20, _step)
        elif on_done:
            on_done()
    win.after(20, _step)

def _anim_zoom(win, cv, img_id, x_final, y_final, cw, ch, on_done=None):
    """Zoom depuis le centre : scale 0 -> 1."""
    scale = [0.05]
    cx = x_final + cw // 2
    cy = y_final + ch // 2
    def _step():
        if not win.winfo_exists(): return
        s = scale[0]
        w_ = max(1, int(cw * s)); h_ = max(1, int(ch * s))
        x_ = cx - w_ // 2;       y_ = cy - h_ // 2
        win.geometry(f"{w_}x{h_}+{x_}+{y_}")
        scale[0] = min(1.0, scale[0] + 0.08)
        if scale[0] < 1.0:
            win.after(16, _step)
        else:
            win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
            if on_done: on_done()
    win.geometry(f"1x1+{cx}+{cy}")
    win.after(16, _step)

def _anim_chute(win, cv, img_id, x_final, y_final, cw, ch, on_done=None):
    """Tombe du haut de l'écran avec rebond."""
    y_start = -ch
    y = [float(y_start)]
    vy = [0.0]
    GRAVITY = 18.0; BOUNCE = 0.38; FLOOR = float(y_final)
    bounces = [0]; MAX_BOUNCES = 6  # garde-fou : max 6 rebonds puis on pose
    def _step():
        if not win.winfo_exists(): return
        vy[0] += GRAVITY
        y[0]  += vy[0]
        if y[0] >= FLOOR:
            y[0] = FLOOR
            vy[0] = -abs(vy[0]) * BOUNCE
            bounces[0] += 1
            if abs(vy[0]) < 4 or bounces[0] >= MAX_BOUNCES:
                win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
                if on_done: on_done()
                return
        win.geometry(f"{cw}x{ch}+{x_final}+{int(y[0])}")
        win.after(16, _step)
    win.geometry(f"{cw}x{ch}+{x_final}+{y_start}")
    win.after(16, _step)

def _anim_spin(win, cv, img_id, x_final, y_final, cw, ch, base_img, on_done=None):
    """Rotation de 0° à 360° en zoomant depuis 0. Fenêtre invisible jusqu'à la 1ère frame."""
    angle = [0.0]; scale = [0.0]
    win.attributes("-alpha", 0.0)   # invisible jusqu'à la 1ère frame rendue
    def _step():
        if not win.winfo_exists(): return
        angle[0] += 18.0; scale[0] = min(1.0, scale[0] + 0.06)
        try:
            rotated = base_img.rotate(-angle[0], expand=True, resample=Image.BICUBIC)
            s = scale[0]
            new_w = max(1, int(rotated.width * s))
            new_h = max(1, int(rotated.height * s))
            resized = rotated.resize((new_w, new_h), Image.LANCZOS)
            photo = ImageTk.PhotoImage(resized)
            cx_ = x_final + cw // 2; cy_ = y_final + ch // 2
            win.geometry(f"{new_w}x{new_h}+{cx_ - new_w//2}+{cy_ - new_h//2}")
            cv.config(width=new_w, height=new_h)
            cv.itemconfig(img_id, image=photo)
            cv._spin_photo = photo
            win.attributes("-alpha", 1.0)   # visible dès la 1ère frame
        except Exception: pass
        if angle[0] < 360.0:
            win.after(16, _step)
        else:
            win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
            cv.config(width=cw, height=ch)
            if on_done: on_done()
    win.geometry(f"1x1+{x_final + cw//2}+{y_final + ch//2}")
    win.after(16, _step)

def _anim_glitch(win, cv, img_id, x_final, y_final, cw, ch, base_img, on_done=None):
    """Distorsion RGB : décalage canal rouge/bleu aléatoire."""
    win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
    frames = [0]
    MAX_FRAMES = 14
    def _step():
        if not win.winfo_exists(): return
        intensity = max(1, int(20 * (1 - frames[0] / MAX_FRAMES)))
        try:
            r, g, b = base_img.convert("RGB").split()
            dx = random.randint(-intensity, intensity)
            dy = random.randint(-intensity, intensity)
            r2 = Image.new("L", base_img.size, 0)
            r2.paste(r, (dx, dy))
            b2 = Image.new("L", base_img.size, 0)
            b2.paste(b, (-dx, -dy))
            merged = Image.merge("RGB", (r2, g, b2))
            photo = ImageTk.PhotoImage(merged)
            cv.itemconfig(img_id, image=photo)
            cv._glitch_photo = photo
        except Exception: pass
        frames[0] += 1
        if frames[0] < MAX_FRAMES:
            win.after(40, _step)
        elif on_done:
            # restore image propre
            try:
                photo = ImageTk.PhotoImage(base_img.convert("RGB"))
                cv.itemconfig(img_id, image=photo)
                cv._glitch_photo = photo
            except Exception: pass
            on_done()
    win.after(40, _step)

def _anim_tremble(win, cv, img_id, x_final, y_final, cw, ch, on_done=None):
    """Tremblement intense pendant ~1.5s."""
    end_time = time.time() + 1.5
    def _step():
        if not win.winfo_exists(): return
        if time.time() < end_time:
            ox = random.randint(-12, 12)
            oy = random.randint(-12, 12)
            win.geometry(f"{cw}x{ch}+{x_final+ox}+{y_final+oy}")
            win.after(30, _step)
        else:
            win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
            if on_done: on_done()
    win.geometry(f"{cw}x{ch}+{x_final}+{y_final}")
    win.after(30, _step)

def _anim_yeet(win, cv, img_id, x_final, y_final, cw, ch, sw, sh, on_done=None):
    """Traverse l'écran en diagonale depuis un côté jusqu'à l'autre."""
    # départ depuis gauche hors écran, cible milieu, puis sort à droite
    x = [float(-cw)]
    y = [float(random.randint(50, max(51, sh - ch - 50)))]
    vx = (sw + cw) / 22.0
    vy = (y_final - y[0]) / 22.0
    step_n = [0]; TOTAL = 22
    def _step():
        if not win.winfo_exists():
            if on_done:
                try: on_done()
                except Exception: pass
            return
        x[0] += vx; y[0] += vy; step_n[0] += 1
        win.geometry(f"{cw}x{ch}+{int(x[0])}+{int(y[0])}")
        if step_n[0] < TOTAL:
            win.after(16, _step)
        else:
            try: win.destroy()
            except: pass
            if on_done:
                try: on_done()
                except Exception: pass
    win.geometry(f"{cw}x{ch}+{int(x[0])}+{int(y[0])}")
    win.after(16, _step)


# ══════════════════════════════════════════════════════════════════════════════
#  PRÉPARATION + AFFICHAGE OVERLAY
# ══════════════════════════════════════════════════════════════════════════════

def _prepare_and_show(app_root, content, config, _done_cb=None):
    """Prépare et affiche un overlay. _done_cb est appelé quand l'overlay
    est terminé (barre vide ou yeet fini), pour débloquer la queue."""
    def _signal_done():
        if _done_cb:
            try: _done_cb()
            except Exception: pass

    try:
        msg_type       = content.get("type", "text")
        img_url        = content.get("image_url", "")
        vid_url        = content.get("video_url", "")
        raw_text       = content.get("text", "")
        sent_timestamp = content.get("sent_timestamp", None)
        author         = content.get("author", "")
        mention_map    = content.get("mention_map", {})
        username_local = config.get("username", "").strip().lower()

        # ── Parse les commandes dans le texte ─────────────────────────────
        targets, animation, modifiers, vol_override, dur_override, clean_text = parse_commands(raw_text, mention_map)

        # ── Ciblage : si des @pseudo sont présents, vérifier si on est concerné
        if targets:
            if username_local not in targets:
                log(f"[BOT] Message ignore (cible: {targets}, moi: {username_local})")
                return

        duration = dur_override if dur_override is not None else int(config.get("display_duration", 8))
        volume   = config.get("volume", 50)
        if vol_override is not None:
            volume = int(vol_override * 100)

        BAR_H = 10
        # sw/sh doivent être lus dans le thread tkinter principal ; on les lit ici
        # depuis _prepare_and_show qui est déjà appelé via _thread_pool (non-tkinter),
        # mais app_root.winfo_screenwidth() est thread-safe en lecture sur Windows.
        sw = app_root.winfo_screenwidth()
        sh = app_root.winfo_screenheight()
        # Sécurité : si winfo renvoie 1 (pas encore mappé), utiliser valeurs par défaut
        if sw <= 1: sw = 1920
        if sh <= 1: sh = 1080

        if config.get("announce_sound", True) and volume > 0:
            threading.Thread(target=_play_announce_sound, args=(volume,), daemon=True).start()

        sess = _get_session()

        # ── IMAGE ──────────────────────────────────────────────────────────
        if msg_type == "image" and img_url:
            cached = _cache_get(img_url)
            raw = cached if cached else sess.get(img_url, timeout=8).content
            if not cached: _cache_put(img_url, raw)

            src = Image.open(io.BytesIO(raw)).convert("RGB")

            # Taille de base selon #grand / #petit — appliquée UNE SEULE FOIS ici
            if "grand" in modifiers:
                src.thumbnail((int(sw*0.80), int(sh*0.80)), Image.LANCZOS)
            elif "petit" in modifiers:
                src.thumbnail((180, 180), Image.LANCZOS)
            else:
                src.thumbnail((600, 500), Image.LANCZOS)

            # _apply_modifiers sans grand/petit (déjà traités)
            src = _apply_modifiers(src, modifiers - {"grand", "petit"}, sw, sh)

            iw, ih = src.size
            # Police adaptée à la taille de l'image (#petit → fonte réduite)
            fs = max(16, iw // 13); font = _load_font(fs)
            CW = iw; CH = ih + BAR_H

            # Coins arrondis sur l'image source
            src_rounded = _round_corners(src.convert("RGBA"), radius=16)

            canvas_img = Image.new("RGBA", (CW, CH), (255, 0, 255, 255))
            canvas_img.alpha_composite(src_rounded, (0, 0))
            d = ImageDraw.Draw(canvas_img)
            if clean_text:
                lines = _wrap_text(clean_text, iw, font, d, fs)
                _draw_caption(d, lines, font, fs, iw, ih, BAR_H)

            _av_url = content.get("avatar_url", "")
            _author_name = author
            if _author_name:
                try:
                    badge = _build_author_badge(_author_name, _av_url, CW)
                    bx = 8; by = 8
                    canvas_img.alpha_composite(badge, (bx, by))
                except Exception as _be:
                    log(f"[BADGE] {_be}")

            # [PERF] split alpha une seule fois
            _ci_r, _ci_g, _ci_b, _ci_a = canvas_img.split()
            final_img = Image.new("RGB", (CW, CH), (255, 0, 255))
            final_img.paste(Image.merge("RGB", (_ci_r, _ci_g, _ci_b)), mask=_ci_a)

            def _show_image(ci=final_img, cw=CW, ch=CH, i_h=ih, bh=BAR_H,
                            anim=animation, mods=modifiers, dur=duration, ts=sent_timestamp):
                try:
                    x, y  = _compute_position(config, sw, sh, cw, ch)
                    # Clamp pour que la fenêtre reste entièrement dans l'écran
                    x = max(0, min(x, sw - cw))
                    y = max(0, min(y, sh - ch))
                    win   = tk.Toplevel(app_root)
                    win.overrideredirect(True)
                    win.attributes("-topmost", True)
                    win.configure(bg="#FF00FF")
                    win.attributes("-transparentcolor", "#FF00FF")
                    win.geometry(f"{cw}x{ch}+{x}+{y}")

                    # yeet: on gère taille différemment
                    if anim == "yeet":
                        win.attributes("-alpha", 1.0)
                    
                    cv_w = tk.Canvas(win, width=cw, height=ch, bg="#FF00FF", highlightthickness=0)
                    cv_w.pack()
                    photo = ImageTk.PhotoImage(ci)
                    img_id = cv_w.create_image(0, 0, anchor="nw", image=photo)
                    bar_id = cv_w.create_rectangle(0, i_h, cw, i_h + bh, fill=C_RED, outline="")
                    win._photo = photo

                    def _start_bar():
                        _animate_bar(win, cv_w, bar_id, i_h, cw, bh, dur, ts, on_done=_signal_done)
                        if anim == "flou":
                            _apply_blur_effect(cv_w, img_id, ci.crop((0,0,cw,i_h)))

                    if anim == "fondu":
                        _anim_fondu(win, cv_w, img_id, x, y, cw, ch, on_done=_start_bar)
                    elif anim == "zoom":
                        _anim_zoom(win, cv_w, img_id, x, y, cw, ch, on_done=_start_bar)
                    elif anim == "chute":
                        _anim_chute(win, cv_w, img_id, x, y, cw, ch, on_done=_start_bar)
                    elif anim == "spin":
                        base = ci.crop((0, 0, cw, i_h))
                        _anim_spin(win, cv_w, img_id, x, y, cw, ch, base, on_done=_start_bar)
                    elif anim == "glitch":
                        base = ci.crop((0, 0, cw, i_h))
                        _anim_glitch(win, cv_w, img_id, x, y, cw, ch, base, on_done=_start_bar)
                    elif anim == "tremble":
                        _anim_tremble(win, cv_w, img_id, x, y, cw, ch, on_done=_start_bar)
                    elif anim == "yeet":
                        _anim_yeet(win, cv_w, img_id, x, y, cw, ch, sw, sh, on_done=_signal_done)
                        return  # yeet auto-détruit la fenêtre
                    else:
                        _start_bar()

                    log(f"[OVERLAY] Image {cw}x{ch} anim={anim} mods={mods}")
                except Exception as e:
                    log(f"[OVERLAY] Image UI error: {e}")
            app_root.after(0, _show_image)

        # ── GIF ────────────────────────────────────────────────────────────
        elif msg_type == "gif" and img_url:
            cached = _cache_get(img_url)
            raw = cached if cached else sess.get(img_url, timeout=12).content
            if not cached: _cache_put(img_url, raw)

            try:
                gif_pil = Image.open(io.BytesIO(raw))
            except Exception as e:
                log(f"[OVERLAY] GIF ouverture impossible: {e}"); return

            # Vérifier que c'est bien un GIF animé
            fmt = getattr(gif_pil, "format", "").upper()
            # Pillow expose n_frames directement pour les GIFs
            n_frames = getattr(gif_pil, "n_frames", 1)
            # Si n_frames == 1 et format pas GIF → image statique déguisée
            # Mais on ne bascule en statique QUE si on est sûr que c'est pas animé
            is_animated = (n_frames > 1)

            if not is_animated:
                # Fallback : traiter comme image statique
                log(f"[OVERLAY] GIF statique détecté ({fmt}, {n_frames} frames), bascule image")
                src = gif_pil.convert("RGB")
                if "grand" in modifiers:
                    src.thumbnail((int(sw*0.80), int(sh*0.80)), Image.LANCZOS)
                elif "petit" in modifiers:
                    src.thumbnail((180, 180), Image.LANCZOS)
                else:
                    src.thumbnail((600, 500), Image.LANCZOS)
                iw, ih = src.size
                CW_FB = iw; CH_FB = ih + BAR_H
                src_r = _round_corners(src.convert("RGBA"), radius=16)
                fb_img = Image.new("RGBA", (CW_FB, CH_FB), (255, 0, 255, 255))
                fb_img.alpha_composite(src_r, (0,0))
                if author:
                    try:
                        b = _build_author_badge(author, content.get("avatar_url",""), CW_FB)
                        fb_img.alpha_composite(b, (8, 8))
                    except Exception: pass
                fb_rgb = Image.new("RGB", (CW_FB, CH_FB), (255, 0, 255))
                fb_rgb.paste(fb_img.convert("RGB"), mask=fb_img.split()[3])
                def _show_fb(ci=fb_rgb, cw=CW_FB, ch=CH_FB, i_h=ih, bh=BAR_H, dur=duration, ts=sent_timestamp):
                    try:
                        x, y = _compute_position(config, sw, sh, cw, ch)
                        win = tk.Toplevel(app_root)
                        win.overrideredirect(True); win.attributes("-topmost", True)
                        win.configure(bg="#FF00FF")
                        win.attributes("-transparentcolor", "#FF00FF")
                        win.geometry(f"{cw}x{ch}+{x}+{y}")
                        cv_w = tk.Canvas(win, width=cw, height=ch, bg="#FF00FF", highlightthickness=0)
                        cv_w.pack()
                        ph = ImageTk.PhotoImage(ci)
                        cv_w.create_image(0, 0, anchor="nw", image=ph)
                        bar_id = cv_w.create_rectangle(0, i_h, cw, i_h+bh, fill=C_RED, outline="")
                        win._photo = ph
                        _animate_bar(win, cv_w, bar_id, i_h, cw, bh, dur, ts, on_done=_signal_done)
                    except Exception as e:
                        log(f"[OVERLAY] GIF-fallback UI error: {e}")
                        _signal_done()
                app_root.after(0, _show_fb)
                return

            # Extraire toutes les frames GIF correctement (gestion delta frames)
            gif_frames = []
            gif_delays = []
            try:
                gif_pil.seek(0)
                gif_size = gif_pil.size
                # Créer un canvas de composition qui accumule les deltas
                canvas = Image.new("RGBA", gif_size, (0, 0, 0, 0))
                prev_canvas = canvas.copy()
                while True:
                    # Lire delay et disposal AVANT de convertir (ils sont dans .info à chaque frame)
                    delay = gif_pil.info.get("duration", 80)
                    gif_delays.append(max(20, int(delay)))
                    disposal = gif_pil.info.get("disposal", 0)

                    # Position de la frame via .tile (format: [(decoder, (x,y,x2,y2), ...)])
                    frame_x, frame_y = 0, 0
                    try:
                        if gif_pil.tile:
                            tile_box = gif_pil.tile[0][1]  # (x, y, x2, y2)
                            frame_x = int(tile_box[0])
                            frame_y = int(tile_box[1])
                    except Exception:
                        frame_x, frame_y = 0, 0

                    # Convertir la frame courante en RGBA
                    frame_rgba = gif_pil.convert("RGBA")

                    # Sauvegarder le canvas avant modification (pour disposal=3)
                    prev_canvas = canvas.copy()

                    # Clamp : éviter que la frame dépasse les bords du canvas (fréquent avec Tenor)
                    fw, fh = frame_rgba.size
                    cw_g, ch_g = gif_size
                    if frame_x + fw > cw_g or frame_y + fh > ch_g:
                        crop_w = min(fw, max(0, cw_g - frame_x))
                        crop_h = min(fh, max(0, ch_g - frame_y))
                        if crop_w <= 0 or crop_h <= 0:
                            # Frame entièrement hors canvas → répéter la frame précédente
                            gif_frames.append(canvas.copy())
                            try:
                                gif_pil.seek(gif_pil.tell() + 1)
                            except EOFError:
                                break
                            continue
                        frame_rgba = frame_rgba.crop((0, 0, crop_w, crop_h))

                    # Composer la frame sur le canvas à sa position
                    canvas_copy = canvas.copy()
                    canvas_copy.alpha_composite(frame_rgba, (frame_x, frame_y))
                    gif_frames.append(canvas_copy.copy())

                    # Mettre à jour le canvas selon la méthode de disposal
                    if disposal == 2:
                        # Restaurer le fond : effacer la zone de la frame en transparent
                        canvas = canvas.copy()
                        clear = Image.new("RGBA", frame_rgba.size, (0, 0, 0, 0))
                        canvas.paste(clear, (frame_x, frame_y))
                    elif disposal == 3:
                        # Restaurer l'état précédent
                        canvas = prev_canvas
                    else:
                        # Disposal 0 ou 1 : conserver le canvas composé
                        canvas = canvas_copy

                    try:
                        gif_pil.seek(gif_pil.tell() + 1)
                    except EOFError:
                        break
            except Exception as e:
                log(f"[OVERLAY] GIF extraction frames: {e}")
                if not gif_frames:
                    return

            # Redimensionner
            sample = gif_frames[0]
            gw, gh = sample.size
            if "grand" in modifiers:
                max_w, max_h = int(sw * 0.80), int(sh * 0.80)
            elif "petit" in modifiers:
                max_w, max_h = 180, 180
            else:
                max_w, max_h = 600, 500
            scale = min(max_w / max(gw, 1), max_h / max(gh, 1), 1.0)
            new_w = max(1, int(gw * scale)); new_h = max(1, int(gh * scale))

            # Préparer les frames redimensionnées + coins arrondis + badge
            _av_url_gif = content.get("avatar_url", "")
            badge_gif = None
            if author:
                try:
                    badge_gif = _build_author_badge(author, _av_url_gif, new_w)
                except Exception: pass

            CW_G = new_w; CH_G = new_h + BAR_H
            processed_frames = []
            for frm in gif_frames:
                f = frm.resize((new_w, new_h), Image.LANCZOS)
                f = _round_corners(f, radius=16)
                bg_f = Image.new("RGBA", (CW_G, CH_G), (255, 0, 255, 255))
                bg_f.alpha_composite(f, (0, 0))
                if badge_gif:
                    bx = 8; by = 8
                    bg_f.alpha_composite(badge_gif.copy(), (bx, by))
                rgb_f = Image.new("RGB", (CW_G, CH_G), (255, 0, 255))
                rgb_f.paste(bg_f.convert("RGB"), mask=bg_f.split()[3])
                processed_frames.append(rgb_f)

            total_ms = sum(gif_delays)

            def _show_gif(frames=processed_frames, delays=gif_delays,
                          cw=CW_G, ch=CH_G, i_h=new_h, bh=BAR_H,
                          anim=animation, dur=duration, ts=sent_timestamp):
                try:
                    x, y = _compute_position(config, sw, sh, cw, ch)
                    x = max(0, min(x, sw - cw))
                    y = max(0, min(y, sh - ch))
                    win = tk.Toplevel(app_root)
                    win.overrideredirect(True)
                    win.attributes("-topmost", True)
                    win.configure(bg="#FF00FF")
                    win.attributes("-transparentcolor", "#FF00FF")
                    win.geometry(f"{cw}x{ch}+{x}+{y}")
                    cv_w = tk.Canvas(win, width=cw, height=ch, bg="#FF00FF", highlightthickness=0)
                    cv_w.pack()

                    # [PERF] Créer les PhotoImage par batch pour éviter freeze sur GIFs longs
                    BATCH = 8
                    photos = [None] * len(frames)
                    for i, f in enumerate(frames[:BATCH]):
                        photos[i] = ImageTk.PhotoImage(f)
                    def _fill_photos(start=BATCH, ph=photos, fr=frames):
                        for i in range(start, min(start + BATCH, len(fr))):
                            ph[i] = ImageTk.PhotoImage(fr[i])
                        if start + BATCH < len(fr):
                            win.after(1, _fill_photos, start + BATCH)
                    if len(frames) > BATCH:
                        win.after(1, _fill_photos)
                    img_id = cv_w.create_image(0, 0, anchor="nw", image=photos[0])
                    bar_id = cv_w.create_rectangle(0, i_h, cw, i_h + bh, fill=C_RED, outline="")

                    # Stocker TOUT sur win pour éviter tout GC
                    win._gif_photos  = photos
                    win._gif_delays  = delays
                    win._gif_idx     = 0
                    win._gif_canvas  = cv_w
                    win._gif_img_id  = img_id
                    win._gif_bar_id  = bar_id
                    win._gif_i_h     = i_h
                    win._gif_cw      = cw
                    win._gif_bh      = bh
                    win._gif_dur     = float(max(1, dur))
                    win._gif_deadline = None  # fixé par _start_gif au démarrage réel

                    # Garde-fou : _signal_done ne doit être appelée qu'une seule fois
                    _gif_done_sent = [False]
                    def _gif_signal_done():
                        if not _gif_done_sent[0]:
                            _gif_done_sent[0] = True
                            _signal_done()

                    def _tick(w=win):
                        if not w.winfo_exists():
                            _gif_signal_done()
                            return
                        # deadline None = animation d'entrée en cours → reschedule sans rien faire
                        if w._gif_deadline is None:
                            w.after(50, w._gif_tick)
                            return
                        now = time.time()
                        if now >= w._gif_deadline:
                            try: w.destroy()
                            except: pass
                            _gif_signal_done()
                            return
                        n = len(w._gif_photos)
                        idx = w._gif_idx % n
                        ph = w._gif_photos[idx]
                        if ph is not None:
                            w._gif_canvas.itemconfig(w._gif_img_id, image=ph)
                        # Si ph est None (batch pas encore chargé), on avance quand même
                        remaining = max(0.0, w._gif_deadline - now)
                        frac = remaining / w._gif_dur
                        w._gif_canvas.coords(w._gif_bar_id, 0, w._gif_i_h,
                                             int(w._gif_cw * frac), w._gif_i_h + w._gif_bh)
                        w._gif_idx += 1
                        delay_ms = w._gif_delays[idx % len(w._gif_delays)]
                        w.after(delay_ms, w._gif_tick)

                    def _start_gif(w=win):
                        w._gif_deadline = time.time() + w._gif_dur
                        w._gif_idx = 0
                        w._gif_tick()  # via win

                    # Stocker _tick sur win pour le protéger du GC
                    win._gif_tick = _tick

                    if anim == "fondu":
                        _anim_fondu(win, cv_w, img_id, x, y, cw, ch, on_done=_start_gif)
                    elif anim == "zoom":
                        _anim_zoom(win, cv_w, img_id, x, y, cw, ch, on_done=_start_gif)
                    elif anim == "chute":
                        _anim_chute(win, cv_w, img_id, x, y, cw, ch, on_done=_start_gif)
                    else:
                        _start_gif()

                    log(f"[OVERLAY] GIF {cw}x{ch} {len(frames)} frames anim={anim}")
                except Exception as e:
                    log(f"[OVERLAY] GIF UI error: {e}")
                    import traceback; log(traceback.format_exc())
            app_root.after(0, _show_gif)


        elif msg_type == "video" and vid_url:
            if not _CV2_OK:
                log("[OVERLAY] cv2 non disponible"); return

            tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".mp4")
            log("[OVERLAY] Telechargement video...")
            with sess.get(vid_url, timeout=30, stream=True) as r:
                for chunk in r.iter_content(chunk_size=65536):
                    tmp.write(chunk)
            tmp.close()
            tmp_path = tmp.name

            cap = cv2.VideoCapture(tmp_path)
            if not cap.isOpened():
                log("[OVERLAY] Impossible d'ouvrir la video")
                os.unlink(tmp_path); return

            fps     = cap.get(cv2.CAP_PROP_FPS) or 25
            total_f = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))
            raw_w   = int(cap.get(cv2.CAP_PROP_FRAME_WIDTH))
            raw_h   = int(cap.get(cv2.CAP_PROP_FRAME_HEIGHT))

            if "grand" in modifiers:
                scale = min(int(sw*0.80)/max(raw_w,1), int(sh*0.80)/max(raw_h,1), 1.0)
            elif "petit" in modifiers:
                scale = min(180/max(raw_w,1), 180/max(raw_h,1), 1.0)
            else:
                scale = min(600/max(raw_w,1), 500/max(raw_h,1), 1.0)

            VW = int(raw_w * scale); VH = int(raw_h * scale)
            CW = VW; CH = VH + BAR_H

            text_overlay = None
            if clean_text:
                fs = max(28, VW // 13); fv = _load_font(fs)
                to_img = Image.new("RGBA", (CW, VH), (0,0,0,0))
                td = ImageDraw.Draw(to_img)
                lines = _wrap_text(clean_text, CW, fv, td, fs)
                _draw_caption(td, lines, fv, fs, CW, VH, 0)
                text_overlay = to_img

            audio_path = None
            if _PYGAME_OK and _FFMPEG_OK and volume > 0:
                try:
                    audio_path = tmp_path.replace(".mp4", "_audio.wav")
                    subprocess.run(
                        [_FFMPEG_BIN, "-y", "-i", tmp_path, "-vn",
                         "-acodec", "pcm_s16le", "-ar", "44100", "-ac", "2", audio_path],
                        stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL
                    )
                    if not (os.path.exists(audio_path) and os.path.getsize(audio_path) > 0):
                        audio_path = None
                    else:
                        log("[SON] Audio extrait OK")
                except Exception as e:
                    log(f"[SON] Erreur extraction audio: {e}"); audio_path = None

            frame_interval = max(1, int(1000 / fps))
            duration_ms    = int(total_f / fps * 1000)
            steps          = max(1, duration_ms // frame_interval)
            target_size    = (VW, VH)

            def _show_video(vw=VW, vh=VH, cw=CW, ch=CH, bh=BAR_H,
                            fi=frame_interval, st=steps, to=text_overlay,
                            ap=audio_path, tp=tmp_path, cp=cap, ts_=target_size,
                            vol=volume, mods=modifiers,
                            duration_ms=duration_ms, frame_interval=frame_interval,
                            _author=author, _av_url=content.get("avatar_url",""),
                            _cfg=config):
                try:
                    x, y = _compute_position(_cfg, sw, sh, cw, ch)
                    win  = tk.Toplevel(app_root)
                    win.overrideredirect(True)
                    win.attributes("-topmost", True)
                    win.geometry(f"{cw}x{ch}+{x}+{y}")
                    win.configure(bg="#FF00FF")
                    win.attributes("-transparentcolor", "#FF00FF")
                    cv_w = tk.Canvas(win, width=cw, height=ch, bg="#FF00FF", highlightthickness=0)
                    cv_w.pack()
                    img_id = cv_w.create_image(0, 0, anchor="nw")
                    bar_id = cv_w.create_rectangle(0, vh, cw, ch, fill=C_RED, outline="")

                    _badge_vid = None
                    if _author:
                        try: _badge_vid = _build_author_badge(_author, _av_url, cw)
                        except Exception: pass

                    snd_ref = [None]
                    # Pré-chargement du son dans un thread pour ne pas bloquer tkinter
                    _snd_ready = [False]
                    _snd_load_err = [False]
                    _audio_start_time = [None]  # horodatage du play()

                    def _preload_sound():
                        if not (ap and _PYGAME_OK):
                            _snd_ready[0] = True
                            return
                        try:
                            snd = pygame.mixer.Sound(ap)
                            snd.set_volume(max(0.0, min(1.0, vol / 100)))
                            snd_ref[0] = snd
                        except Exception as e:
                            log(f"[SON] preload error: {e}")
                            _snd_load_err[0] = True
                        _snd_ready[0] = True

                    threading.Thread(target=_preload_sound, daemon=True).start()

                    def _cleanup():
                        cp.release()
                        if snd_ref[0]:
                            try: snd_ref[0].stop()
                            except: pass
                        for p in [tp, ap]:
                            if p:
                                try: os.unlink(p)
                                except: pass

                    def next_frame(step):
                        if not win.winfo_exists():
                            _cleanup(); _signal_done(); return

                        # Son prêt mais pas encore lancé → on joue et on note l'heure
                        if _snd_ready[0] and _audio_start_time[0] is None:
                            if snd_ref[0] and not _snd_load_err[0]:
                                _audio_start_time[0] = time.time()
                                snd_ref[0].play()
                            else:
                                _audio_start_time[0] = time.time()  # pas de son, on démarre quand même

                        # Sync : si le son a démarré, on positionne la vidéo sur le temps réel écoulé
                        if _audio_start_time[0] is not None:
                            elapsed_ms = (time.time() - _audio_start_time[0]) * 1000
                            cp.set(cv2.CAP_PROP_POS_MSEC, elapsed_ms)

                        ret, frame = cp.read()
                        if not ret:
                            _cleanup()
                            try: win.destroy()
                            except: pass
                            _signal_done()
                            return

                        # step recalculé depuis la position réelle de la vidéo
                        pos_ms = cp.get(cv2.CAP_PROP_POS_MSEC)
                        real_step = max(0, int((duration_ms - pos_ms) / frame_interval))

                        if (frame.shape[1], frame.shape[0]) != ts_:  # [PERF] resize conditionnel
                            frame = cv2.resize(frame, ts_, interpolation=cv2.INTER_LINEAR)
                        frame_rgb = cv2.cvtColor(frame, cv2.COLOR_BGR2RGB)
                        pil_f = Image.fromarray(frame_rgb)
                        # modificateurs video frame par frame
                        if "retourne" in mods:
                            pil_f = pil_f.transpose(Image.FLIP_TOP_BOTTOM)
                        if "miroir" in mods:
                            pil_f = pil_f.transpose(Image.FLIP_LEFT_RIGHT)
                        if "nb" in mods:
                            pil_f = pil_f.convert("L").convert("RGB")
                        if to:
                            pil_f = pil_f.convert("RGBA")
                            pil_f.alpha_composite(to)
                            pil_f = pil_f.convert("RGB")
                        pil_rgba = _round_corners(pil_f.convert("RGBA"), radius=16)
                        canvas_v = Image.new("RGBA", (cw, ch), (255, 0, 255, 255))  # [PERF] fond chroma
                        canvas_v.alpha_composite(pil_rgba, (0, 0))
                        if _badge_vid:
                            bx = 8; by = 8
                            canvas_v.alpha_composite(_badge_vid.copy(), (bx, by))
                        # [PERF] extraction mask une seule fois
                        _cv_r, _cv_g, _cv_b, _cv_a = canvas_v.split()
                        final_v = Image.new("RGB", (cw, ch), (255, 0, 255))
                        final_v.paste(Image.merge("RGB", (_cv_r, _cv_g, _cv_b)), mask=_cv_a)
                        photo = ImageTk.PhotoImage(final_v)
                        cv_w.itemconfig(img_id, image=photo)
                        win._frame_photo = photo
                        frac = 1.0 - (pos_ms / duration_ms) if duration_ms > 0 else 0
                        cv_w.coords(bar_id, 0, vh, int(cw * (1.0 - frac)), ch)
                        if real_step > 0:
                            win.after(fi, next_frame, real_step - 1)
                        else:
                            _cleanup()
                            try: win.destroy()
                            except: pass
                            _signal_done()

                    win.after(fi, next_frame, st)
                    log(f"[OVERLAY] Video {cw}x{ch} {fps:.0f}fps mods={mods}")
                except Exception as e:
                    log(f"[OVERLAY] Video UI error: {e}")
                    import traceback; log(traceback.format_exc())

            app_root.after(0, _show_video)

        # ── TEXTE ──────────────────────────────────────────────────────────
        else:
            if not clean_text:
                _signal_done()  # libérer la queue même si rien à afficher (ex: message "!")
                return
            W = 520; fs = 28; LH = fs + 8; PAD = 16; BH = 10
            font = _load_font(fs)
            dummy = Image.new("RGB", (W, 10)); dd = ImageDraw.Draw(dummy)
            lines = _wrap_text(clean_text, W, font, dd, fs) or [clean_text]
            H = PAD + len(lines) * LH + PAD + BH
            img = Image.new("RGB", (W, H), (18, 18, 28))
            d   = ImageDraw.Draw(img)
            # Dessiner le texte (avec support emoji) via _draw_caption
            _draw_caption(d, lines, font, fs, W, H - BH, BH)
            d.rectangle([0, H - BH, W, H], fill=(18, 18, 28))

            img_rgba = _round_corners(img.convert("RGBA"), radius=14)
            _av_url_txt = content.get("avatar_url", "")
            if author:
                try:
                    badge_txt = _build_author_badge(author, _av_url_txt, W)
                    bx_t = 8; by_t = 8
                    img_rgba.alpha_composite(badge_txt, (bx_t, by_t))
                except Exception: pass
            # [PERF] split alpha une seule fois
            _tr, _tg, _tb, _ta = img_rgba.split()
            txt_final = Image.new("RGB", (W, H), (255, 0, 255))
            txt_final.paste(Image.merge("RGB", (_tr, _tg, _tb)), mask=_ta)

            def _show_text(si=txt_final, sw_=W, sh_=H, bh=BH, anim=animation, dur=duration, ts=sent_timestamp):
                try:
                    photo = ImageTk.PhotoImage(si)
                    x, y  = _compute_position(config, sw, sh, sw_, sh_)
                    win   = tk.Toplevel(app_root)
                    win.overrideredirect(True)
                    win.attributes("-topmost", True)
                    win.geometry(f"{sw_}x{sh_}+{x}+{y}")
                    win.configure(bg="#FF00FF")
                    win.attributes("-transparentcolor", "#FF00FF")
                    cv_w = tk.Canvas(win, width=sw_, height=sh_, bg="#FF00FF", highlightthickness=0)
                    cv_w.pack()
                    img_id = cv_w.create_image(0, 0, anchor="nw", image=photo)
                    by0    = sh_ - bh
                    bar_id = cv_w.create_rectangle(0, by0, sw_, sh_, fill=C_RED, outline="")
                    win._photo = photo

                    def _start_bar():
                        _animate_bar(win, cv_w, bar_id, by0, sw_, bh, dur, ts, on_done=_signal_done)

                    if anim == "fondu":
                        _anim_fondu(win, cv_w, img_id, x, y, sw_, sh_, on_done=_start_bar)
                    elif anim == "zoom":
                        _anim_zoom(win, cv_w, img_id, x, y, sw_, sh_, on_done=_start_bar)
                    elif anim == "chute":
                        _anim_chute(win, cv_w, img_id, x, y, sw_, sh_, on_done=_start_bar)
                    elif anim == "tremble":
                        _anim_tremble(win, cv_w, img_id, x, y, sw_, sh_, on_done=_start_bar)
                    elif anim == "yeet":
                        _anim_yeet(win, cv_w, img_id, x, y, sw_, sh_, sw, sh, on_done=_signal_done)
                        return
                    else:
                        _start_bar()
                except Exception as e:
                    log(f"[OVERLAY] Texte UI error: {e}")
            app_root.after(0, _show_text)

    except Exception as e:
        log(f"[OVERLAY] Error: {e}")
        import traceback; log(traceback.format_exc())
        _signal_done()   # libérer la queue même en cas d'erreur


# ── overlay class ──────────────────────────────────────────────────────────
class Overlay:
    def show(self, content, config):
        log(f"[OVERLAY] Queue: {content.get('type')}")
        _overlay_queue.put({"content": content, "config": config})
        # ── Historique ────────────────────────────────────────────────────
        _push_history({
            "ts":     datetime.now(),
            "type":   content.get("type", "?"),
            "author": content.get("author", ""),
            "avatar": content.get("avatar_url", ""),
            "text":   content.get("text", ""),
            "url":    content.get("image_url", content.get("video_url", "")),
            "anim":   config.get("animation", ""),
            "pos":    config.get("position", ""),
        })

overlay_instance = Overlay()
bot_config = {}

GIF_EXTS   = {".gif"}
IMAGE_EXTS = {".png",".jpg",".jpeg",".gif",".webp",".jfif",".bmp",".tiff",".tif",".avif",".heic",".ico",".ppm",".pgm"}
VIDEO_EXTS = {".mp4",".mov",".webm",".mkv",".avi"}

# ── bot Discord ────────────────────────────────────────────────────────────
bot = None; bot_loop = None
_bot_lock = threading.Lock()   # empêche les appels simultanés start/stop

def start_bot(token, cfg):
    global bot, bot_loop, bot_config

    if not _bot_lock.acquire(blocking=False):
        log("[BOT] Déjà en cours de connexion/déconnexion, ignoré.")
        return

    bot_config = cfg

    class MemedropBot(commands.Bot):
        def __init__(self):
            intents = discord.Intents.all()
            super().__init__(command_prefix="§§", intents=intents)

        async def on_ready(self):
            log(f"[BOT] Connecte: {self.user}")
            log(f"[BOT] Channel: {bot_config.get('channel_id','???')}")

        async def on_message(self, message):
            ch_id_check = bot_config.get("channel_id", "").strip()
            if not ch_id_check or str(message.channel.id) == ch_id_check:
                cmd = message.content.strip().lower()
                if cmd == "!skip":
                    skip_to_next_overlay()
                    log("[BOT] Skip : passage au suivant")
                    return
                if cmd == "!clear":
                    clear_overlay()
                    log("[BOT] Clear : queue videe")
                    return

            if message.author == self.user: return
            ch_id = bot_config.get("channel_id", "").strip()
            if not ch_id or str(message.channel.id) != ch_id: return

            author     = message.author.display_name
            avatar_url = str(message.author.display_avatar.url) if message.author.display_avatar else ""
            msg_text   = message.content or ""
            sent_ts    = message.created_at.timestamp()
            log(f"[BOT] {author}: {msg_text[:60]}")

            mention_map = {str(u.id): u.display_name.lower() for u in message.mentions}
            if message.guild:
                for m in message.guild.members:
                    mention_map.setdefault(str(m.id), m.display_name.lower())

            def _push(payload):
                payload["sent_timestamp"] = sent_ts
                payload["mention_map"]    = mention_map
                overlay_instance.show(payload, bot_config)

            # ── Pièces jointes ─────────────────────────────────────────────
            for att in message.attachments:
                ext   = os.path.splitext(att.filename.lower())[1]
                ctype = (att.content_type or "").lower()
                if ext in GIF_EXTS or ctype.startswith("image/gif"):
                    _push({"type":"gif","author":author,"image_url":att.url,"avatar_url":avatar_url,"text":msg_text}); return
                if ext in IMAGE_EXTS or ctype.startswith("image/"):
                    _push({"type":"image","author":author,"image_url":att.url,"avatar_url":avatar_url,"text":msg_text}); return
                if ext in VIDEO_EXTS or ctype.startswith("video/"):
                    _push({"type":"video","author":author,"video_url":att.url,"avatar_url":avatar_url,"text":msg_text}); return

            # ── Embeds Discord ─────────────────────────────────────────────
            for emb in message.embeds:
                emb_type = (emb.type or "").lower()
                if emb_type == "gifv":
                    tenor_gif_url = None
                    if emb.url and "tenor.com" in emb.url:
                        try:
                            m_tenor = re.search(r'-(\d+)(?:/)?$', emb.url.rstrip('/'))
                            if not m_tenor:
                                m_tenor = re.search(r'[/-](\d{6,})(?:[^/]*)$', emb.url)
                            if m_tenor:
                                tenor_id = m_tenor.group(1)
                                api_url = (
                                    f"https://tenor.googleapis.com/v2/posts"
                                    f"?ids={tenor_id}"
                                    f"&key=AIzaSyAyimkuYQYF_FXVALexPuGQctUWRURdCDc"
                                    f"&media_filter=gif,mediumgif"
                                )
                                loop = asyncio.get_event_loop()
                                def _fetch_tenor(u=api_url):
                                    return _get_session().get(u, timeout=6).json()
                                tenor_data = await loop.run_in_executor(None, _fetch_tenor)
                                results = tenor_data.get("results", [])
                                if results:
                                    fmts = results[0].get("media_formats", {})
                                    tenor_gif_url = (
                                        fmts.get("gif") or fmts.get("mediumgif") or {}
                                    ).get("url")
                        except Exception as _te:
                            log(f"[TENOR] API error: {_te}")
                        if not tenor_gif_url and emb.thumbnail and emb.thumbnail.url:
                            _thumb = str(emb.thumbnail.url)
                            _tl = _thumb.lower().split("?")[0]
                            if _tl.endswith(".gif") or ".gif" in _tl:
                                tenor_gif_url = _thumb
                    if tenor_gif_url:
                        _push({"type":"gif","author":author,"image_url":tenor_gif_url,"avatar_url":avatar_url,"text":""}); return
                    if emb.video and emb.video.url:
                        _push({"type":"video","author":author,"video_url":str(emb.video.url),"avatar_url":avatar_url,"text":""}); return
                    elif emb.url:
                        gif_url = str(emb.url)
                        if emb.thumbnail and emb.thumbnail.url:
                            gif_url = str(emb.thumbnail.url)
                        _push({"type":"image","author":author,"image_url":gif_url,"avatar_url":avatar_url,"text":""}); return
                elif emb_type == "image":
                    img_u = ""
                    if emb.thumbnail and emb.thumbnail.url:
                        img_u = str(emb.thumbnail.url)
                    elif emb.image and emb.image.url:
                        img_u = str(emb.image.url)
                    if img_u:
                        ext_e = os.path.splitext(img_u.lower().split("?")[0])[1]
                        t = "gif" if ext_e in GIF_EXTS else "image"
                        _push({"type":t,"author":author,"image_url":img_u,"avatar_url":avatar_url,"text":""}); return

            # ── URLs dans le texte ─────────────────────────────────────────
            for url in re.findall(r'https?://\S+', msg_text):
                url = url.rstrip(".,!?)>")
                if re.search(r'tenor\.com/view/', url) or re.search(r'giphy\.com/gifs/', url):
                    continue
                path_part = url.lower().split("?")[0]
                ext = os.path.splitext(path_part)[1]
                if ext in GIF_EXTS:
                    _push({"type":"gif","author":author,"image_url":url,"avatar_url":avatar_url,"text":""}); return
                if ext in IMAGE_EXTS:
                    _push({"type":"image","author":author,"image_url":url,"avatar_url":avatar_url,"text":""}); return
                if ext in VIDEO_EXTS:
                    _push({"type":"video","author":author,"video_url":url,"avatar_url":avatar_url,"text":""}); return
                try:
                    loop = asyncio.get_event_loop()
                    def _do_head(u=url):
                        s = _get_session()
                        return s.head(u, timeout=5, allow_redirects=True).headers.get("Content-Type","").lower()
                    ctype = await loop.run_in_executor(None, _do_head)
                    if ctype.startswith("image/gif"):
                        _push({"type":"gif","author":author,"image_url":url,"avatar_url":avatar_url,"text":""}); return
                    if ctype.startswith("image/"):
                        _push({"type":"image","author":author,"image_url":url,"avatar_url":avatar_url,"text":""}); return
                    if ctype.startswith("video/"):
                        _push({"type":"video","author":author,"video_url":url,"avatar_url":avatar_url,"text":""}); return
                except: pass

            if msg_text and bot_config.get("show_text", True):
                _push({"type":"text","author":author,"text":msg_text,"avatar_url":avatar_url})

            await self.process_commands(message)

    def run():
        global bot, bot_loop
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
        bot_loop = loop
        try:
            bot = MemedropBot()
            loop.run_until_complete(bot.start(token))
        except asyncio.CancelledError:
            pass
        except Exception as e:
            log(f"[BOT] Erreur run: {e}")
        finally:
            try:
                pending = asyncio.all_tasks(loop)
                for task in pending:
                    task.cancel()
                if pending:
                    loop.run_until_complete(asyncio.gather(*pending, return_exceptions=True))
            except Exception:
                pass
            try:
                loop.close()
            except Exception:
                pass
            log("[BOT] Loop ferme proprement.")
            _bot_lock.release()   # ← libéré ici, une fois tout arrêté

    threading.Thread(target=run, daemon=True).start()

def stop_bot():
    global bot, bot_loop
    if bot and bot_loop and not bot_loop.is_closed():
        future = asyncio.run_coroutine_threadsafe(bot.close(), bot_loop)
        try:
            future.result(timeout=5)
        except Exception:
            pass

