# Couleur d'accent (rouge par défaut, modifiable)
_ACCENT = "#e63333"

def _set_accent(hex_color: str):
    global _ACCENT, C_RED, C_RED_H
    _ACCENT = hex_color
    C_RED   = hex_color
    C_RED_H = _lighten(hex_color, 0.2)

def _lighten(hex_color: str, factor: float) -> str:
    """Éclaircit une couleur hex d'un facteur 0-1."""
    try:
        h = hex_color.lstrip("#")
        r, g, b = int(h[0:2],16), int(h[2:4],16), int(h[4:6],16)
        r = min(255, int(r + (255-r)*factor))
        g = min(255, int(g + (255-g)*factor))
        b = min(255, int(b + (255-b)*factor))
        return f"#{r:02x}{g:02x}{b:02x}"
    except Exception:
        return hex_color

def _darken(hex_color: str, factor: float) -> str:
    """Assombrit une couleur hex d'un facteur 0-1."""
    try:
        h = hex_color.lstrip("#")
        r, g, b = int(h[0:2],16), int(h[2:4],16), int(h[4:6],16)
        r = max(0, int(r * (1-factor)))
        g = max(0, int(g * (1-factor)))
        b = max(0, int(b * (1-factor)))
        return f"#{r:02x}{g:02x}{b:02x}"
    except Exception:
        return hex_color

# Initialisé avec la valeur par défaut ; sera écrasé au démarrage depuis la config
C_RED   = _ACCENT
C_RED_H = _lighten(_ACCENT, 0.2)

