# ── Cercle lissé (antialiasing via PIL ou multi-passes tkinter) ────────────
def _draw_smooth_circle(cv, x, y, r, fill, bg, outline_color=None, outline_width=0,
                        check=False, font=None):
    """
    Dessine un cercle lissé sur un tk.Canvas.
    Utilise PIL/ImageTk si disponible pour un vrai antialiasing,
    sinon fallback multi-passes tkinter.
    cv     : tk.Canvas cible
    x, y   : centre du cercle
    r      : rayon
    fill   : couleur de remplissage (#rrggbb)
    bg     : couleur de fond du canvas (#rrggbb)
    outline_color : couleur du bord sélection (None = pas de bord)
    outline_width : épaisseur du bord
    check  : afficher un ✓ au centre
    font   : tuple de police pour le ✓
    """
    cv.delete("all")
    # ── Tentative PIL (meilleur résultat) ───────────────────────────────────
    try:
        from PIL import Image as _PILImage, ImageDraw as _PILDraw, ImageTk as _PILTk
        size   = r * 2 + 4          # petit padding pour le bord
        scale  = 4                  # supersampling ×4
        img    = _PILImage.new("RGBA", (size * scale, size * scale), (0, 0, 0, 0))
        draw   = _PILDraw.Draw(img)
        pad    = 2 * scale
        if outline_color and outline_width:
            ow = outline_width * scale
            draw.ellipse([pad - ow, pad - ow,
                          size * scale - pad + ow, size * scale - pad + ow],
                         fill=outline_color, outline=None)
        draw.ellipse([pad, pad, size * scale - pad, size * scale - pad],
                     fill=fill, outline=None)
        img = img.resize((size, size), _PILImage.LANCZOS)
        # Composer sur fond bg
        bg_img = _PILImage.new("RGBA", (size, size),
                               tuple(int(bg.lstrip("#")[i:i+2], 16) for i in (0, 2, 4)) + (255,))
        bg_img.paste(img, mask=img.split()[3])
        photo = _PILTk.PhotoImage(bg_img)
        cv.create_image(size // 2, size // 2, image=photo, anchor="center")
        cv._photo_ref = photo   # éviter le garbage collect
        if check:
            # Coche vectorielle PIL antialiasée
            sc = scale * 2  # supersampling supplémentaire pour la coche
            ck = _PILImage.new("RGBA", (size * sc, size * sc), (0, 0, 0, 0))
            ckd = _PILDraw.Draw(ck)
            cx, cy = size * sc // 2, size * sc // 2
            t = max(2, int(r * sc * 0.13))  # épaisseur trait
            # Points de la coche (relatifs au centre, échelle sc)
            s = int(r * sc * 0.45)
            p1 = (cx - s,        cy)
            p2 = (cx - s//4,     cy + s*2//3)
            p3 = (cx + s,        cy - s*2//3)
            ckd.line([p1, p2], fill=(255,255,255,255), width=t)
            ckd.line([p2, p3], fill=(255,255,255,255), width=t)
            ck = ck.resize((size, size), _PILImage.LANCZOS)
            bg_img.paste(ck, mask=ck.split()[3])
            photo = _PILTk.PhotoImage(bg_img)
            cv.create_image(size // 2, size // 2, image=photo, anchor="center")
            cv._photo_ref = photo
        return
    except Exception:
        pass
    # ── Fallback : multi-passes tkinter ─────────────────────────────────────
    def _hex_lerp(c1, c2, t):
        r1,g1,b1 = int(c1[1:3],16), int(c1[3:5],16), int(c1[5:7],16)
        r2,g2,b2 = int(c2[1:3],16), int(c2[3:5],16), int(c2[5:7],16)
        return "#{:02x}{:02x}{:02x}".format(
            int(r1+(r2-r1)*t), int(g1+(g2-g1)*t), int(b1+(b2-b1)*t))
    if outline_color and outline_width:
        cv.create_oval(x-r-outline_width, y-r-outline_width,
                       x+r+outline_width, y+r+outline_width,
                       fill=outline_color, outline="")
    # Cercle principal avec bord fondu sur 2 px
    cv.create_oval(x-r,   y-r,   x+r,   y+r,   fill=fill, outline="")
    cv.create_oval(x-r+1, y-r+1, x+r-1, y+r-1, fill=fill, outline="")
    # Anneau de fondu bord extérieur (1 px)
    fade = _hex_lerp(fill, bg, 0.5)
    cv.create_oval(x-r, y-r, x+r, y+r, fill="", outline=fade, width=1)
    if check:
        # Fallback : coche tkinter (moins belle mais acceptable)
        cv.create_line(x-r//3, y, x-r//8, y+r//3, fill="white", width=2, capstyle="round")
        cv.create_line(x-r//8, y+r//3, x+r//2, y-r//3, fill="white", width=2, capstyle="round")


# ── interface ──────────────────────────────────────────────────────────────
def _build_memedrop_app_class():
    class MemedropApp(ctk.CTk):
        def __init__(self):
            super().__init__()
            self.config_data = load_config()
            self.bot_running = False
            self.title("FileScreen")
            self.geometry("580x720")
            self.resizable(False, False)
            self.configure(fg_color=C_BG)
            # Lissage des polices : force le scaling DPI Windows (ClearType via GDI+)
            try:
                self.tk.call('tk', 'scaling', self.tk.call('tk', 'scaling'))
                import ctypes
                ctypes.windll.shcore.SetProcessDpiAwareness(1)
            except Exception:
                pass
            try:
                import base64 as _b64ico, io as _ioico, tempfile as _tmp, struct as _st
                from PIL import Image as _Iico
                _full_raw = _Iico.open(_ioico.BytesIO(_b64ico.b64decode(_LOGO_B64_256))).convert("RGBA")
                _icon_raw = _Iico.open(_ioico.BytesIO(_b64ico.b64decode(_LOGO_B64_48))).convert("RGBA")
                _bg = (13, 13, 13, 255)
                def _sized(src, s):
                    c = _Iico.new("RGBA", (s, s), _bg)
                    t = src.copy(); t.thumbnail((s-4, s-4), _Iico.LANCZOS)
                    c.alpha_composite(t, ((s-t.width)//2, (s-t.height)//2))
                    return c.convert("RGBA")
                _pairs = [(16,_icon_raw),(24,_icon_raw),(32,_icon_raw),(48,_icon_raw),
                          (64,_full_raw),(128,_full_raw),(256,_full_raw)]
                _imgs = [_sized(src, s) for s, src in _pairs]
                def _png(img):
                    buf = _ioico.BytesIO(); img.save(buf, "PNG"); return buf.getvalue()
                def _make_ico(images):
                    n = len(images)
                    hdr = _st.pack("<HHH", 0, 1, n)
                    off = 6 + n * 16
                    entries, blobs = [], []
                    for img in images:
                        b = _png(img)
                        entries.append((img.width, img.height, len(b), off))
                        blobs.append(b); off += len(b)
                    d = b"".join(_st.pack("<BBBBHHII",
                        0 if w>=256 else w, 0 if h>=256 else h,
                        0, 0, 1, 32, bl, of)
                        for w, h, bl, of in entries)
                    return hdr + d + b"".join(blobs)
                _ico_tmp = _tmp.NamedTemporaryFile(suffix=".ico", delete=False)
                _ico_tmp.write(_make_ico(_imgs)); _ico_tmp.close()
                self.iconbitmap(_ico_tmp.name)
                self._icon_tmp_path = _ico_tmp.name
            except Exception as _e:
                log(f"[ICON] {_e}")
            self._build_ui()
            self.protocol("WM_DELETE_WINDOW", self._hide_to_tray)
            self._tray_icon = None
            self._start_tray()

        def _start_tray(self):
            try:
                import pystray
                from PIL import Image as _PILtray
                import base64 as _b64t, io as _iot
                import threading as _thr
                try:
                    _img = _PILtray.open(_iot.BytesIO(_b64t.b64decode(_LOGO_B64_48))).convert("RGBA")
                    _bg = _PILtray.new("RGBA", (64, 64), (13, 13, 13, 255))
                    _img.thumbnail((60, 60), _PILtray.LANCZOS)
                    _bg.alpha_composite(_img, ((64 - _img.width) // 2, (64 - _img.height) // 2))
                    _img = _bg.convert("RGB")
                except Exception:
                    _img = _PILtray.new("RGB", (64, 64), (230, 51, 51))
                menu = pystray.Menu(
                    pystray.MenuItem("Ouvrir FileScreen", self._show_from_tray, default=True),
                    pystray.Menu.SEPARATOR,
                    pystray.MenuItem("Quitter", self._quit_app),
                )
                self._tray_icon = pystray.Icon("FileScreen", _img, "FileScreen", menu)
                _thr.Thread(target=self._tray_icon.run, daemon=True).start()
                log("[TRAY] Icône systray démarrée.")
            except Exception as _e:
                self._tray_icon = None
                log(f"[TRAY] pystray non disponible : {_e}")

        def _hide_to_tray(self):
            if self._tray_icon is not None:
                self.withdraw()
            else:
                self._quit_app()

        def _show_from_tray(self, icon=None, item=None):
            self.after(0, self.deiconify)
            self.after(0, self.lift)

        def _quit_app(self, icon=None, item=None):
            if self._tray_icon:
                try:
                    self._tray_icon.stop()
                except Exception:
                    pass
                self._tray_icon = None
            self.after(0, self.destroy)

        # ══════════════════════════════════════════════════════════════════
        #  BUILD UI — layout : sidebar gauche + zone contenu droite
        # ══════════════════════════════════════════════════════════════════
        def _build_ui(self):
            self._value_labels   = []
            self._section_lines  = []
            self._active_tab     = "Réglages"

            # Racine : deux colonnes
            root_frame = tk.Frame(self, bg=C_BG)
            root_frame.pack(fill="both", expand=True)

            # ── Sidebar ──────────────────────────────────────────────────
            self._sidebar = tk.Frame(root_frame, bg=C_SIDEBAR, width=68)
            self._sidebar.pack(side="left", fill="y")
            self._sidebar.pack_propagate(False)

            # ── Zone droite ───────────────────────────────────────────────
            right = tk.Frame(root_frame, bg=C_BG)
            right.pack(side="left", fill="both", expand=True)

            self._build_sidebar()
            self._build_topbar(right)
            self._build_content(right)
            self.after(0, self._refresh_accent)

        def _build_sidebar(self):
            """Sidebar avec icônes d'onglets + bouton connect en bas."""
            import math, base64 as _b64s, io as _ios
            from PIL import Image as _PILs, ImageTk as _ITks

            # Logo PNG sans fond, affiché dans un tk.Label
            logo_frame = tk.Frame(self._sidebar, bg=C_SIDEBAR, width=68, height=72)
            logo_frame.pack(pady=(8, 4))
            logo_frame.pack_propagate(False)

            def _load_sidebar_logo():
                try:
                    raw = _PILs.open(_ios.BytesIO(_b64s.b64decode(_LOGO_SPLASH_B64))).convert("RGBA")
                    # Redimensionner pour tenir dans 52x52 max (sidebar 68px wide)
                    raw.thumbnail((52, 52), _PILs.LANCZOS)
                    # Coller sur fond C_SIDEBAR pour éviter transparence grise tkinter
                    h_col = C_SIDEBAR.lstrip("#")
                    bg_r, bg_g, bg_b = int(h_col[0:2],16), int(h_col[2:4],16), int(h_col[4:6],16)
                    bg = _PILs.new("RGBA", raw.size, (bg_r, bg_g, bg_b, 255))
                    bg.paste(raw, mask=raw.split()[3])
                    photo = _ITks.PhotoImage(bg.convert("RGB"))
                    lbl = tk.Label(logo_frame, image=photo, bg=C_SIDEBAR, bd=0)
                    lbl.image = photo  # garder ref
                    lbl.place(relx=0.5, rely=0.5, anchor="center")
                    self._logo_cv_sidebar = lbl
                    self._logo_sidebar_photo = photo
                except Exception as e:
                    log(f"[LOGO SIDEBAR] {e}")

            logo_frame.after(10, _load_sidebar_logo)

            # Séparateur
            tk.Frame(self._sidebar, bg=C_BORD, height=1).pack(fill="x", padx=10, pady=(0,6))

            # Icônes des onglets
            _tabs = [
                ("Réglages",   "⚙",  "Réglages"),
                ("Connexion",  "🔗", "Connexion"),
                ("Commandes",  "📋", "Commandes"),
                ("Historique", "📜", "Historique"),
            ]
            self._tab_btns       = {}
            self._tab_icon_cvs   = {}

            for tab_id, icon, label in _tabs:
                self._make_sidebar_btn(tab_id, icon, label)

            # Spacer
            tk.Frame(self._sidebar, bg=C_SIDEBAR).pack(fill="y", expand=True)

            # Bouton connect en bas de la sidebar
            self._sidebar_connect_cv = tk.Canvas(
                self._sidebar, width=44, height=44,
                bg=C_SIDEBAR, highlightthickness=0, cursor="hand2")
            self._sidebar_connect_cv.pack(pady=(0, 14))
            self._draw_connect_btn(connected=False)
            self._sidebar_connect_cv.bind("<Button-1>", lambda e: self._toggle_bot())

        def _make_sidebar_btn(self, tab_id, icon, label):
            cv = tk.Canvas(self._sidebar, width=52, height=52,
                           bg=C_SIDEBAR, highlightthickness=0, cursor="hand2")
            cv.pack(pady=2)
            is_active = (tab_id == self._active_tab)
            bg_col = C_SIDEBAR_SEL if is_active else C_SIDEBAR
            # Fond arrondi
            cv.create_rectangle(4, 4, 48, 48, fill=bg_col, outline="", tags="bg")
            # Icône
            cv.create_text(26, 19, text=icon, font=(_FONT, 16), fill=C_RED if is_active else C_SUB,
                           tags="icon")
            # Label mini
            cv.create_text(26, 41, text=label[:3].upper(), font=(_FONT, 7, "bold"),
                           fill=C_RED if is_active else C_MUTED, tags="lbl")
            cv.bind("<Button-1>", lambda e, t=tab_id: self._switch_tab(t))
            cv.bind("<Enter>", lambda e, c=cv, t=tab_id: self._sidebar_hover(c, t, True))
            cv.bind("<Leave>", lambda e, c=cv, t=tab_id: self._sidebar_hover(c, t, False))
            self._tab_btns[tab_id] = cv
            self._tab_icon_cvs[tab_id] = (icon, label)

        def _sidebar_hover(self, cv, tab_id, entering):
            if tab_id == self._active_tab:
                return
            col = C_SIDEBAR_SEL if entering else C_SIDEBAR
            try:
                cv.itemconfig("bg", fill=col)
            except Exception:
                pass

        def _draw_connect_btn(self, connected):
            cv = self._sidebar_connect_cv
            col = "#2a6644" if connected else C_RED
            # Cercle PIL lissé
            _draw_smooth_circle(cv, 22, 22, 20, col, C_SIDEBAR)
            # Icône vectorielle PIL centrée optiquement
            try:
                SC  = 6
                SZ  = 44 * SC
                img = Image.new("RGBA", (SZ, SZ), (0, 0, 0, 0))
                d   = ImageDraw.Draw(img)
                cx, cy = SZ // 2, SZ // 2
                if connected:
                    # Carré stop centré
                    hs = int(SZ * 0.18)
                    d.rectangle([cx-hs, cy-hs, cx+hs, cy+hs], fill=(255,255,255,255))
                else:
                    # Triangle play centré optiquement (légèrement décalé à droite visuellement)
                    r = int(SZ * 0.22)
                    pts = [
                        (cx - int(r*0.6), cy - r),
                        (cx - int(r*0.6), cy + r),
                        (cx + int(r*0.95), cy),
                    ]
                    d.polygon(pts, fill=(255,255,255,255))
                img = img.resize((44, 44), Image.LANCZOS)
                bg_c = tuple(int(C_SIDEBAR.lstrip("#")[i:i+2],16) for i in (0,2,4))+(255,)
                bg  = Image.new("RGBA", (44, 44), bg_c)
                bg.paste(img, mask=img.split()[3])
                photo = ImageTk.PhotoImage(bg)
                cv.create_image(22, 22, anchor="center", image=photo)
                cv._icon_ref = photo
            except Exception:
                icon = "⏹" if connected else "▶"
                cv.create_text(22, 22, text=icon, font=(_FONT, 14, "bold"), fill="white")

        def _build_topbar(self, parent):
            """Barre du haut : titre + statut — CTkLabel pour le lissage."""
            bar = tk.Frame(parent, bg=C_TOPBAR)
            bar.pack(fill="x")

            # Colonne gauche : titre + breadcrumb
            left = tk.Frame(bar, bg=C_TOPBAR)
            left.pack(side="left", fill="y", padx=(18, 0), pady=10)

            self._lbl_page_title = ctk.CTkLabel(
                left, text="Réglages",
                font=(_FONT, 16, "bold"), text_color=C_TEXT, anchor="w")
            self._lbl_page_title.pack(anchor="w")

            self._lbl_page_sub = ctk.CTkLabel(
                left, text="FileScreen  ›  Réglages",
                font=(_FONT, 9), text_color=C_MUTED, anchor="w")
            self._lbl_page_sub.pack(anchor="w", pady=(1, 0))

            # Colonne droite : pastille + statut
            right = tk.Frame(bar, bg=C_TOPBAR)
            right.pack(side="right", padx=18, pady=0)

            dot_row = tk.Frame(right, bg=C_TOPBAR)
            dot_row.pack(anchor="e", expand=True, pady=18)

            self._status_dot = tk.Canvas(dot_row, width=8, height=8,
                                          bg=C_TOPBAR, highlightthickness=0)
            self._status_dot.pack(side="left", pady=2)
            _draw_smooth_circle(self._status_dot, 4, 4, 3, C_MUTED, C_TOPBAR)

            self._lbl_status_top = ctk.CTkLabel(
                dot_row, text="  Déconnecté",
                font=(_FONT, 10), text_color=C_MUTED)
            self._lbl_status_top.pack(side="left")

            # Ligne de séparation bas
            tk.Frame(parent, bg=C_BORD, height=1).pack(fill="x")

        def _build_content(self, parent):
            self._content = ctk.CTkScrollableFrame(
                parent, fg_color=C_BG, border_width=0,
                scrollbar_button_color=C_BORD,
                scrollbar_button_hover_color=C_SUB)
            self._content.pack(fill="both", expand=True)

            def _on_mousewheel(event):
                canvas = getattr(self._content, "_parent_canvas", None)
                if canvas is None:
                    for child in self._content.winfo_children():
                        if isinstance(child, tk.Canvas):
                            canvas = child; break
                if canvas:
                    canvas.yview_scroll(int(-1*(event.delta/120)) * 8, "units")
            self.bind_all("<MouseWheel>", _on_mousewheel)
            self._switch_tab("Réglages")

        # ── Navigation ────────────────────────────────────────────────────
        def _switch_tab(self, name):
            self._active_tab = name
            self._section_lines = []
            if not hasattr(self, "_value_labels"):
                self._value_labels = []
            else:
                self._value_labels.clear()

            # Mettre à jour la sidebar
            if hasattr(self, "_tab_btns"):
                for tab_id, cv in self._tab_btns.items():
                    try:
                        if not cv.winfo_exists(): continue
                        is_act = (tab_id == name)
                        cv.itemconfig("bg",   fill=C_SIDEBAR_SEL if is_act else C_SIDEBAR)
                        cv.itemconfig("icon", fill=C_RED if is_act else C_SUB)
                        cv.itemconfig("lbl",  fill=C_RED if is_act else C_MUTED)
                    except Exception:
                        pass

            # Topbar
            if hasattr(self, "_lbl_page_title"):
                try:
                    self._lbl_page_title.configure(text=name)
                    self._lbl_page_sub.configure(text=f"FileScreen  ›  {name}")
                except Exception:
                    pass

            for w in self._content.winfo_children():
                w.destroy()
            {"Réglages":   self._tab_reglages,
             "Connexion":  self._tab_connexion,
             "Commandes":  self._tab_commandes,
             "Historique": self._tab_historique}[name]()

        # ── Composants de base ────────────────────────────────────────────
        def _section(self, label):
            row = tk.Frame(self._content, bg=C_BG)
            row.pack(fill="x", padx=20, pady=(18, 5))
            line = tk.Frame(row, bg=C_RED, width=3, height=13)
            line.pack(side="left", padx=(0, 8))
            if not hasattr(self, "_section_lines"):
                self._section_lines = []
            self._section_lines.append(line)
            tk.Label(row, text=label, font=(_FONT, 9, "bold"),
                     fg=C_SUB, bg=C_BG).pack(side="left", anchor="w")

        def _card(self, parent=None, pady=4):
            p = parent or self._content
            f = ctk.CTkFrame(p, fg_color=C_CARD, corner_radius=14,
                             border_width=1, border_color=C_BORD)
            f.pack(fill="x", padx=16, pady=pady)
            return f

        def _divider(self, parent):
            tk.Frame(parent, bg=C_BORD, height=1).pack(fill="x", padx=16)

        def _row(self, parent, label, sublabel=None):
            row = tk.Frame(parent, bg=C_CARD)
            row.pack(fill="x", padx=18, pady=(12, 2 if sublabel else 12))
            lf = tk.Frame(row, bg=C_CARD)
            lf.pack(side="left")
            tk.Label(lf, text=label, font=(_FONT, 12), fg=C_TEXT, bg=C_CARD).pack(anchor="w")
            if sublabel:
                tk.Label(lf, text=sublabel, font=(_FONT, 9), fg=C_MUTED, bg=C_CARD).pack(anchor="w", pady=(1, 6))
            return row

        def _slider_row(self, parent, label, from_, to, initial, fmt, sublabel=None, on_change=None):
            row = self._row(parent, label, sublabel)
            lbl = ctk.CTkLabel(row, text=fmt(initial), font=(_FONT, 12, "bold"),
                               text_color=C_RED, width=42)
            lbl.pack(side="right", padx=(0, 4))
            def _sl_cmd(v, l=lbl, f=fmt):
                l.configure(text=f(int(v)))
                if on_change: on_change()
            sl = ctk.CTkSlider(row, from_=from_, to=to, width=130,
                               button_color=C_RED, button_hover_color=C_RED_H,
                               progress_color=C_RED, command=_sl_cmd)
            sl.set(initial)
            sl.pack(side="right", padx=8)
            if not hasattr(self, "_value_labels") or self._value_labels is None:
                self._value_labels = []
            self._value_labels.append(lbl)
            return sl

        def _switch_row(self, parent, label, initial, sublabel=None, on_change=None):
            row = self._row(parent, label, sublabel)
            sw = ctk.CTkSwitch(row, text="", width=46,
                               button_color=C_RED, button_hover_color=C_RED_H,
                               progress_color=C_RED,
                               command=on_change if on_change else lambda: None)
            if initial:
                sw.select()
            sw.pack(side="right", padx=14)
            return sw

        # ══════════════════════════════════════════════════════════════════
        #  ONGLET RÉGLAGES
        # ══════════════════════════════════════════════════════════════════
        def _tab_reglages(self):
            # ── AUDIO ─────────────────────────────────────────────────────
            self._section("AUDIO")
            card = self._card()
            self._sl_vol   = self._slider_row(card, "Volume", 0, 100,
                                               self.config_data.get("volume", 50),
                                               lambda v: f"{v}%",
                                               on_change=self._auto_save)
            self._divider(card)
            self._sw_sound = self._switch_row(card, "Son d'annonce",
                                               self.config_data.get("announce_sound", True),
                                               "Bip à chaque nouveau média",
                                               on_change=self._auto_save)
            self._divider(card)
            self._sw_text  = self._switch_row(card, "Messages texte",
                                               self.config_data.get("show_text", True),
                                               on_change=self._auto_save)

            # ── AFFICHAGE ──────────────────────────────────────────────────
            self._section("AFFICHAGE")
            card2 = self._card()
            self._sl_dur = self._slider_row(card2, "Durée d'affichage", 1, 30,
                                             self.config_data.get("display_duration", 8),
                                             lambda v: f"{v}s",
                                             "Ne s'applique pas aux vidéos",
                                             on_change=self._auto_save)

            # ── POSITION ───────────────────────────────────────────────────
            self._section("POSITION DE L'OVERLAY")
            card3 = self._card()
            self._sw_random = self._switch_row(card3, "Position aléatoire",
                                                self.config_data.get("random_position", False),
                                                on_change=self._auto_save)
            self._divider(card3)

            # Grille de position 3×2 style moderne
            pos_wrap = tk.Frame(card3, bg=C_CARD)
            pos_wrap.pack(fill="x", padx=18, pady=(10, 14))
            tk.Label(pos_wrap, text="Position fixe", font=(_FONT, 9), fg=C_MUTED, bg=C_CARD
                     ).pack(anchor="w", pady=(0, 6))
            grid = tk.Frame(pos_wrap, bg=C_CARD)
            grid.pack(anchor="w")
            self._selected_pos = self.config_data.get("position", "haut")
            self._pos_btns = {}
            positions = [
                ["haut gauche", "haut",   "haut droite"],
                ["bas gauche",  "centre", "bas droite"],
            ]
            for ri, row_p in enumerate(positions):
                for ci, pos in enumerate(row_p):
                    is_act = (pos == self._selected_pos)
                    btn = tk.Canvas(grid, width=56, height=40,
                                   bg=C_CARD,
                                   highlightthickness=0,
                                   cursor="hand2")
                    btn.grid(row=ri, column=ci, padx=3, pady=3)

                    def _draw_pos_btn(cv, active, p=pos):
                        cv.delete("all")
                        fill_hex = C_RED  if active else C_CARD2
                        bord_hex = C_RED  if active else C_BORD
                        W, H = 56, 40
                        SC = 3  # supersampling
                        try:
                            from PIL import Image as _PI, ImageDraw as _PD, ImageTk as _PT
                            def _hx(h):
                                return tuple(int(h.lstrip("#")[i:i+2],16) for i in (0,2,4))+(255,)
                            img = _PI.new("RGBA", (W*SC, H*SC), (0,0,0,0))
                            d   = _PD.Draw(img)
                            r   = 8*SC
                            # Bordure
                            d.rounded_rectangle([0,0,W*SC-1,H*SC-1], radius=r,
                                                fill=_hx(bord_hex), outline=None)
                            # Remplissage intérieur (1px inset)
                            bw = SC
                            d.rounded_rectangle([bw,bw,W*SC-1-bw,H*SC-1-bw], radius=max(1,r-bw),
                                                fill=_hx(fill_hex), outline=None)
                            img = img.resize((W, H), _PI.LANCZOS)
                            bg_c = tuple(int(C_CARD.lstrip("#")[i:i+2],16) for i in (0,2,4))+(255,)
                            bg  = _PI.new("RGBA", (W, H), bg_c)
                            bg.paste(img, mask=img.split()[3])
                            photo = _PT.PhotoImage(bg)
                            cv.create_image(0, 0, anchor="nw", image=photo)
                            cv._photo_ref = photo
                        except Exception:
                            # Fallback tkinter simple (rectangle plein)
                            cv.create_rectangle(1, 1, W-1, H-1, fill=fill_hex,
                                                outline=bord_hex, width=1)

                        short = {"haut gauche":"↖", "haut":"↑", "haut droite":"↗",
                                 "bas gauche":"↙",  "centre":"●","bas droite":"↘"}
                        short2 = {"haut gauche":"H.G","haut":"Haut","haut droite":"H.D",
                                  "bas gauche":"B.G","centre":"Ctr","bas droite":"B.D"}
                        cv.create_text(28, 14, text=short.get(p, p),
                                       font=(_FONT, 13), fill="white" if active else C_SUB,
                                       tags="arrow")
                        cv.create_text(28, 30, text=short2.get(p, p[:3]),
                                       font=(_FONT, 7), fill="white" if active else C_MUTED,
                                       tags="lbl")

                    _draw_pos_btn(btn, is_act)
                    btn._draw_fn = _draw_pos_btn
                    btn.bind("<Button-1>", lambda e, p=pos: self._sel_pos(p))
                    self._pos_btns[pos] = btn

            # ── COULEUR D'ACCENT ───────────────────────────────────────────
            self._section("COULEUR D'ACCENT")
            card4 = self._card()
            accent_wrap = tk.Frame(card4, bg=C_CARD)
            accent_wrap.pack(fill="x", padx=18, pady=14)
            tk.Label(accent_wrap, text="Thème de l'interface", font=(_FONT, 9),
                     fg=C_MUTED, bg=C_CARD).pack(anchor="w", pady=(0, 8))
            swatch_row = tk.Frame(accent_wrap, bg=C_CARD)
            swatch_row.pack(anchor="w")
            self._accent_var = getattr(self, "_accent_var",
                                       self.config_data.get("accent_color", "#e63333"))
            self._swatch_btns = {}
            for col_hex, col_name in ACCENT_PRESETS:
                is_active = (col_hex == self._accent_var)
                sw_cv = tk.Canvas(swatch_row, width=34, height=34,
                                  bg=C_CARD, highlightthickness=0)
                sw_cv.pack(side="left", padx=3)
                _draw_smooth_circle(sw_cv, 17, 17, 14, col_hex, C_CARD,
                                    outline_color="white" if is_active else None,
                                    outline_width=3 if is_active else 0,
                                    check=is_active, font=(_FONT, 13, "bold"))
                sw_cv.bind("<Button-1>", lambda e, h=col_hex: self._pick_accent(h))
                sw_cv.configure(cursor="hand2")
                self._swatch_btns[col_hex] = sw_cv

            # padding bas
            ctk.CTkFrame(self._content, fg_color="transparent", height=14).pack()

        def _sel_pos(self, pos):
            self._selected_pos = pos
            self._auto_save()
            for p, btn in self._pos_btns.items():
                try:
                    if not btn.winfo_exists(): continue
                    is_act = (p == pos)
                    if hasattr(btn, "_draw_fn"):
                        btn._draw_fn(btn, is_act)
                    else:
                        btn.configure(bg=C_RED if is_act else C_CARD2,
                                      highlightbackground=C_RED if is_act else C_BORD)
                        btn.itemconfig("arrow", fill="white" if is_act else C_SUB)
                        btn.itemconfig("lbl",   fill="white" if is_act else C_MUTED)
                except Exception:
                    pass

        # ══════════════════════════════════════════════════════════════════
        #  ONGLET CONNEXION
        # ══════════════════════════════════════════════════════════════════
        def _tab_connexion(self):
            self._section("BOT DISCORD")
            card = self._card()

            tk.Label(card, text="Token du bot", font=(_FONT, 9), fg=C_MUTED, bg=C_CARD
                     ).pack(anchor="w", padx=18, pady=(14, 2))
            self._entry_token = ctk.CTkEntry(
                card, placeholder_text="Colle ton token ici…", height=40,
                fg_color=C_CARD2, border_color=C_BORD, show="*", font=(_FONT, 12))
            self._entry_token.pack(fill="x", padx=16, pady=(0, 4))
            self._entry_token.insert(0, self.config_data.get("token", ""))

            def _toggle_show():
                cur = self._entry_token.cget("show")
                self._entry_token.configure(show="" if cur else "*")

            def _make_eye_btn(parent):
                """Icône œil seule pour afficher/masquer le token."""
                SZ = 28
                SC = 6
                from PIL import Image as _PI, ImageDraw as _PD, ImageTk as _PT

                def _draw_eye(visible=True):
                    img = _PI.new("RGBA", (SZ * SC, SZ * SC), (0, 0, 0, 0))
                    d = _PD.Draw(img)
                    cx, cy = SZ * SC // 2, SZ * SC // 2
                    ew, eh = int(SZ * SC * 0.85), int(SZ * SC * 0.45)
                    # Contour œil
                    d.ellipse([cx - ew//2, cy - eh//2, cx + ew//2, cy + eh//2],
                              outline=(190, 190, 210, 255), width=SC + 1)
                    # Pupille
                    pr = int(SZ * SC * 0.12)
                    d.ellipse([cx - pr, cy - pr, cx + pr, cy + pr],
                              fill=(190, 190, 210, 255))
                    if not visible:
                        # Barre diagonale rouge
                        pad = int(SZ * SC * 0.08)
                        d.line([(pad, pad), (SZ * SC - pad, SZ * SC - pad)],
                               fill=(220, 70, 70, 255), width=SC + 2)
                    img = img.resize((SZ, SZ), _PI.LANCZOS)
                    bg_c = tuple(int(C_CARD.lstrip("#")[i:i+2], 16) for i in (0,2,4)) + (255,)
                    bg = _PI.new("RGBA", (SZ, SZ), bg_c)
                    bg.paste(img, mask=img.split()[3])
                    return _PT.PhotoImage(bg.convert("RGB"))

                try:
                    _img_visible = _draw_eye(visible=True)
                    _img_hidden  = _draw_eye(visible=False)
                    _state = [True]   # True = token masqué (show="*")

                    eye_cv = tk.Canvas(parent, width=SZ, height=SZ,
                                       bg=C_CARD, highlightthickness=0, cursor="hand2")
                    eye_cv.pack(anchor="e", padx=16, pady=(0, 10))
                    eye_cv.create_image(SZ//2, SZ//2, anchor="center", image=_img_hidden)
                    eye_cv._refs = [_img_visible, _img_hidden]

                    def _on_click(e=None):
                        _state[0] = not _state[0]
                        img = _img_hidden if _state[0] else _img_visible
                        eye_cv.delete("all")
                        eye_cv.create_image(SZ//2, SZ//2, anchor="center", image=img)
                        _toggle_show()

                    eye_cv.bind("<Button-1>", _on_click)
                except Exception:
                    ctk.CTkButton(parent, text="●", width=32, height=28,
                        fg_color=C_CARD2, hover_color=C_BORD, corner_radius=6,
                        font=(_FONT, 14), command=_toggle_show).pack(anchor="e", padx=16, pady=(0,10))

            _make_eye_btn(card)

            self._divider(card)

            tk.Label(card, text="ID du salon", font=(_FONT, 9), fg=C_MUTED, bg=C_CARD
                     ).pack(anchor="w", padx=18, pady=(10, 2))
            self._entry_channel = ctk.CTkEntry(
                card, placeholder_text="Ex : 1234567890123456789",
                height=40, fg_color=C_CARD2, border_color=C_BORD, font=(_FONT, 12))
            self._entry_channel.pack(fill="x", padx=16, pady=(0, 14))
            self._entry_channel.insert(0, self.config_data.get("channel_id", ""))

            self._section("PROFIL")
            card2 = self._card()
            tk.Label(card2, text="Ton pseudo (pour le ciblage @pseudo)", font=(_FONT, 9),
                     fg=C_MUTED, bg=C_CARD).pack(anchor="w", padx=18, pady=(14, 2))
            self._entry_username = ctk.CTkEntry(
                card2, placeholder_text="Ton pseudo Discord",
                height=40, fg_color=C_CARD2, border_color=C_BORD, font=(_FONT, 12))
            self._entry_username.pack(fill="x", padx=16, pady=(0, 14))
            self._entry_username.insert(0, self.config_data.get("username", ""))

            ctk.CTkFrame(self._content, fg_color="transparent", height=4).pack()
            ctk.CTkButton(self._content, text="Sauvegarder la configuration",
                height=46, fg_color=C_RED, hover_color=C_RED_H, corner_radius=12,
                font=(_FONT, 13, "bold"), command=self._save_connection
            ).pack(fill="x", padx=16, pady=(2, 4))

            # ── Statut ────────────────────────────────────────────────────
            self._section("STATUT DE CONNEXION")
            card3 = self._card()
            status_row = tk.Frame(card3, bg=C_CARD)
            status_row.pack(fill="x", padx=18, pady=14)

            dot_cv = tk.Canvas(status_row, width=10, height=10, bg=C_CARD,
                               highlightthickness=0)
            dot_cv.pack(side="left", pady=4)
            dot_col = C_GREEN if self.bot_running else C_MUTED
            _draw_smooth_circle(dot_cv, 5, 5, 4, dot_col, C_CARD)
            self._conn_dot_cv = dot_cv

            self._lbl_conn = ctk.CTkLabel(
                status_row,
                text="  Connecté" if self.bot_running else "  Déconnecté",
                font=(_FONT, 13, "bold"),
                text_color=C_GREEN if self.bot_running else C_MUTED)
            self._lbl_conn.pack(side="left")

            self._btn_toggle = ctk.CTkButton(
                status_row,
                text="⏹  Déconnecter" if self.bot_running else "▶  Se connecter",
                width=150, height=36,
                fg_color="#2e3440" if self.bot_running else C_RED,
                hover_color="#3b4252" if self.bot_running else C_RED_H,
                corner_radius=10, font=(_FONT, 12, "bold"),
                command=self._toggle_bot_from_tab)
            self._btn_toggle.pack(side="right")

            ch = self.config_data.get("channel_id", "") or "Non configuré"
            tk.Label(card3, text=f"Salon : #{ch}", font=(_FONT, 9),
                     fg=C_SUB, bg=C_CARD).pack(anchor="w", padx=18, pady=(0, 12))

            # ── Dépendances ───────────────────────────────────────────────
            self._section("DÉPENDANCES")
            card4 = self._card()
            if _FFMPEG_OK:
                src = "static-ffmpeg" if "static" in str(_FFMPEG_BIN).lower() else "système"
                self._dep_row(card4, "ffmpeg", f"OK  ({src})", True)
            else:
                self._dep_row(card4, "ffmpeg", "Absent — son vidéo désactivé", False)
                tk.Label(card4, text="→  pip install static-ffmpeg",
                         font=(_FONT, 9), fg=C_MUTED, bg=C_CARD
                         ).pack(anchor="w", padx=18, pady=(0, 10))

        def _dep_row(self, parent, name, status, ok):
            row = tk.Frame(parent, bg=C_CARD)
            row.pack(fill="x", padx=18, pady=8)
            dot = tk.Canvas(row, width=8, height=8, bg=C_CARD, highlightthickness=0)
            dot.pack(side="left", pady=5)
            _draw_smooth_circle(dot, 4, 4, 3, C_GREEN if ok else C_RED, C_CARD)
            tk.Label(row, text=f"  {name}", font=(_FONT, 11, "bold"),
                     fg=C_TEXT, bg=C_CARD).pack(side="left")
            tk.Label(row, text=f"  {status}", font=(_FONT, 10),
                     fg=C_GREEN if ok else C_RED, bg=C_CARD).pack(side="left")

        def _save_connection(self):
            self.config_data["token"]      = self._entry_token.get().strip()
            self.config_data["channel_id"] = self._entry_channel.get().strip()
            self.config_data["username"]   = self._entry_username.get().strip()
            save_config(self.config_data)
            global bot_config
            bot_config.update(self.config_data)
            log("[CONFIG] Connexion sauvegardée")

        def _refresh_conn_status(self):
            """Met à jour tous les widgets liés au statut de connexion."""
            connected = self.bot_running
            col = C_GREEN if connected else C_MUTED
            # Topbar label
            if hasattr(self, "_lbl_status_top"):
                try: self._lbl_status_top.configure(
                    text="  Connecté" if connected else "  Déconnecté",
                    text_color=col)
                except Exception: pass
            # Topbar dot — redraw smooth
            if hasattr(self, "_status_dot"):
                try:
                    if self._status_dot.winfo_exists():
                        _draw_smooth_circle(self._status_dot, 4, 4, 3, col, C_TOPBAR)
                except Exception: pass
            # Bouton sidebar
            if hasattr(self, "_sidebar_connect_cv"):
                try: self._draw_connect_btn(connected)
                except Exception: pass
            # Onglet Connexion — label
            if hasattr(self, "_lbl_conn"):
                try: self._lbl_conn.configure(
                    text="  Connecté" if connected else "  Déconnecté",
                    text_color=col)
                except Exception: pass
            # Onglet Connexion — dot
            if hasattr(self, "_conn_dot_cv"):
                try:
                    if self._conn_dot_cv.winfo_exists():
                        _draw_smooth_circle(self._conn_dot_cv, 5, 5, 4, col, C_CARD)
                except Exception: pass
            # Bouton toggle
            if hasattr(self, "_btn_toggle"):
                try: self._btn_toggle.configure(
                    text="⏹  Déconnecter" if connected else "▶  Se connecter",
                    fg_color="#2e3440" if connected else C_RED,
                    hover_color="#3b4252" if connected else C_RED_H)
                except Exception: pass




